export enum ClientStatus {
  ACTIVE = 'Ativo',
  SEMI_ACTIVE = 'Semi-ativo',
  INACTIVE = 'Inativo'
}

export interface ClientRecord {
  id: string;
  representativeName: string;
  city: string;
  state: string;
  population: number;
  status: ClientStatus;
  lastPurchaseDate: string; // YYYY-MM-DD
}

export interface RepViewRow {
  city: string;
  state: string;
  positiveCount: number;
  population: number;
}

export interface CityViewRow {
  representativeName: string;
  active: number;
  semiActive: number;
  inactive: number;
  total: number;
}

import { ClientRecord, ClientStatus } from '../types';

const CITIES = [
  { name: 'AGUDOS', uf: 'SP', pop: 37401 },
  { name: 'AREALVA', uf: 'SP', pop: 8613 },
  { name: 'BAURU', uf: 'SP', pop: 379297 },
  { name: 'BOTUCATU', uf: 'SP', pop: 148130 },
  { name: 'BARIRI', uf: 'SP', pop: 35558 },
  { name: 'JAU', uf: 'SP', pop: 151881 },
  { name: 'LENCOIS PAULISTA', uf: 'SP', pop: 68990 },
  { name: 'PEDERNEIRAS', uf: 'SP', pop: 47111 },
  { name: 'PIRATININGA', uf: 'SP', pop: 13765 },
  { name: 'MARILIA', uf: 'SP', pop: 240590 },
];

const REPS = [
  'DINA',
  'FABIANA',
  'MAIANE PONTES',
  'PAOLA CAMACHO',
  'PAULO RODRIGO',
  'PEDRO HENRIQUE',
  'ROSI SILVA',
  'TIAGO NUNES',
  'WILSON LUIZ'
];

export const generateMockData = (): ClientRecord[] => {
  const data: ClientRecord[] = [];

  // Generate 500 random records
  for (let i = 0; i < 500; i++) {
    const cityObj = CITIES[Math.floor(Math.random() * CITIES.length)];
    const rep = REPS[Math.floor(Math.random() * REPS.length)];

    // Weighted random status
    const rand = Math.random();
    let status = ClientStatus.ACTIVE;
    if (rand > 0.6) status = ClientStatus.SEMI_ACTIVE;
    if (rand > 0.8) status = ClientStatus.INACTIVE;

    // Random date within last 2 years
    const date = new Date();
    date.setDate(date.getDate() - Math.floor(Math.random() * 700));

    data.push({
      id: `CLI-${i}`,
      representativeName: rep,
      city: cityObj.name,
      state: cityObj.uf,
      population: cityObj.pop,
      status: status,
      lastPurchaseDate: date.toISOString().split('T')[0]
    });
  }
  return data;
};

export const MOCK_DATA = generateMockData();

import React, { useState, useMemo } from 'react';
import { ClientRecord, RepViewRow, ClientStatus } from '../types';
import { MOCK_DATA } from '../services/mockData';

interface RepresentativeTabProps {
  onExport: (data: any[], filename: string) => void;
}

const RepresentativeTab: React.FC<RepresentativeTabProps> = ({ onExport }) => {
  const [selectedRep, setSelectedRep] = useState<string>('DINA');
  const [startDate, setStartDate] = useState('2023-01-01');
  const [endDate, setEndDate] = useState(new Date().toISOString().split('T')[0]);

  // Extract unique reps
  const representatives = useMemo(() => 
    Array.from(new Set(MOCK_DATA.map(d => d.representativeName))).sort(),
  []);

  // Filter and Aggregate Data
  const tableData = useMemo(() => {
    // 1. Filter by Rep and Date
    const filtered = MOCK_DATA.filter(item => {
      const matchRep = item.representativeName === selectedRep;
      const matchDate = item.lastPurchaseDate >= startDate && item.lastPurchaseDate <= endDate;
      // Image 1 implies "Positivados" which usually means Active or bought recently
      const isPositive = item.status === ClientStatus.ACTIVE; 
      return matchRep && matchDate && isPositive;
    });

    // 2. Group by City
    const cityMap = new Map<string, RepViewRow>();

    filtered.forEach(item => {
      const key = `${item.city} - ${item.state}`;
      if (!cityMap.has(key)) {
        cityMap.set(key, {
          city: item.city,
          state: item.state,
          positiveCount: 0,
          population: item.population
        });
      }
      const entry = cityMap.get(key)!;
      entry.positiveCount += 1;
    });

    return Array.from(cityMap.values()).sort((a, b) => a.city.localeCompare(b.city));
  }, [selectedRep, startDate, endDate]);

  const totalPositivated = tableData.reduce((acc, curr) => acc + curr.positiveCount, 0);
  const totalPop = tableData.reduce((acc, curr) => acc + curr.population, 0);

  const handleExport = () => {
    const csvData = tableData.map(row => ({
      'Cidade/UF': `${row.city} - ${row.state}`,
      'Positivação': row.positiveCount,
      'Habitantes': row.population
    }));
    onExport(csvData, `Positivacao_${selectedRep}_${startDate}_${endDate}`);
  };

  return (
    <div className="flex flex-col gap-4">
      {/* Header / Filters similar to Image 1 */}
      <div className="bg-yellow-300 p-2 border border-yellow-400 shadow-sm">
        <h2 className="text-xl font-bold text-blue-900 mb-2 text-center uppercase">
          Curva ABC Millenium Utilidades Domesticas LTDA
        </h2>

        <div className="flex flex-wrap md:flex-nowrap justify-between items-end gap-4 bg-white/50 p-2 rounded">
          <div className="w-full md:w-1/3">
            <label className="block text-xs font-bold text-gray-700 uppercase">Representante</label>
            <select 
              value={selectedRep}
              onChange={(e) => setSelectedRep(e.target.value)}
              className="w-full p-1 border border-gray-400 bg-blue-100 text-sm"
            >
              {representatives.map(r => <option key={r} value={r}>{r}</option>)}
            </select>
          </div>

          <div className="flex gap-2 items-center text-sm">
            <div className="flex flex-col">
              <span className="font-bold text-right">De:</span>
              <span className="font-bold text-right">Até:</span>
            </div>
            <div className="flex flex-col gap-1">
              <input 
                type="date" 
                value={startDate} 
                onChange={(e) => setStartDate(e.target.value)}
                className="border border-gray-300 px-1 text-sm"
              />
              <input 
                type="date" 
                value={endDate} 
                onChange={(e) => setEndDate(e.target.value)}
                className="border border-gray-300 px-1 text-sm"
              />
            </div>
          </div>

          <button 
            onClick={handleExport}
            className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded text-sm font-bold flex items-center gap-2 shadow"
          >
            <i className="fas fa-file-excel"></i> Exportar
          </button>
        </div>
      </div>

      {/* Table - Image 1 Style */}
      <div className="overflow-x-auto border border-black">
        <table className="w-full text-sm font-sans">
          <thead>
            <tr className="bg-black text-white">
              <th className="text-left p-2 border-r border-gray-600">Cidades/UF <i className="fas fa-caret-down ml-1"></i></th>
              <th className="text-right p-2 border-r border-gray-600">Positivação</th>
              <th className="text-right p-2">Habitantes</th>
            </tr>
          </thead>
          <tbody>
            {tableData.length === 0 ? (
              <tr><td colSpan={3} className="p-4 text-center text-gray-500">Nenhum dado encontrado</td></tr>
            ) : (
              tableData.map((row, idx) => (
                <tr key={idx} className={idx % 2 === 0 ? "bg-blue-50" : "bg-blue-100"}>
                  <td className="p-1 px-2 border-r border-gray-300 font-semibold text-gray-800">
                    {row.city} - {row.state}
                  </td>
                  <td className="p-1 px-2 border-r border-gray-300 text-right">
                    {row.positiveCount}
                  </td>
                  <td className="p-1 px-2 text-right">
                    {row.population.toLocaleString('pt-BR')}
                  </td>
                </tr>
              ))
            )}
          </tbody>
          <tfoot>
            <tr className="bg-black text-white font-bold">
              <td className="p-2">Total Geral</td>
              <td className="p-2 text-right">{totalPositivated}</td>
              <td className="p-2 text-right">{totalPop.toLocaleString('pt-BR')}</td>
            </tr>
          </tfoot>
        </table>
      </div>
    </div>
  );
};

