import React, { useState, useMemo } from 'react';
import { ClientRecord, CityViewRow, ClientStatus } from '../types';
import { MOCK_DATA } from '../services/mockData';

interface CityTabProps {
  onExport: (data: any[], filename: string) => void;
}

const CityTab: React.FC<CityTabProps> = ({ onExport }) => {
  const [selectedCity, setSelectedCity] = useState<string>('BAURU');
  const [startDate, setStartDate] = useState('2022-01-01');
  const [endDate, setEndDate] = useState(new Date().toISOString().split('T')[0]);

  // Extract unique cities
  const cities = useMemo(() => 
    Array.from(new Set(MOCK_DATA.map(d => d.city))).sort(),
  []);

  // Get current city population for header
  const currentCityPop = useMemo(() => {
    const record = MOCK_DATA.find(d => d.city === selectedCity);
    return record ? record.population : 0;
  }, [selectedCity]);

  // Filter and Aggregate Data
  const tableData = useMemo(() => {
    // 1. Filter by City and Date
    const filtered = MOCK_DATA.filter(item => {
      const matchCity = item.city === selectedCity;
      const matchDate = item.lastPurchaseDate >= startDate && item.lastPurchaseDate <= endDate;
      return matchCity && matchDate;
    });

    // 2. Group by Representative
    const repMap = new Map<string, CityViewRow>();

    // Initialize all known reps to show empty rows too (like Excel pivot)? 
    // Or just active ones. Let's do active in this filter to show real data.
    filtered.forEach(item => {
      if (!repMap.has(item.representativeName)) {
        repMap.set(item.representativeName, {
          representativeName: item.representativeName,
          active: 0,
          semiActive: 0,
          inactive: 0,
          total: 0
        });
      }
      const entry = repMap.get(item.representativeName)!;

      if (item.status === ClientStatus.ACTIVE) entry.active++;
      else if (item.status === ClientStatus.SEMI_ACTIVE) entry.semiActive++;
      else if (item.status === ClientStatus.INACTIVE) entry.inactive++;

      entry.total++;
    });

    // Add "Sem Rep" logic if there are unassigned (mock data doesn't have it, but for completeness)

    return Array.from(repMap.values()).sort((a, b) => a.representativeName.localeCompare(b.representativeName));
  }, [selectedCity, startDate, endDate]);

  // Totals
  const totals = tableData.reduce((acc, curr) => ({
    active: acc.active + curr.active,
    semi: acc.semi + curr.semiActive,
    inactive: acc.inactive + curr.inactive,
    total: acc.total + curr.total
  }), { active: 0, semi: 0, inactive: 0, total: 0 });

  const handleExport = () => {
    const csvData = tableData.map(row => ({
      'Representante': row.representativeName,
      'Ativo': row.active,
      'Semi-ativo': row.semiActive,
      'Inativo': row.inactive,
      'Total Geral': row.total
    }));
    onExport(csvData, `Status_Cidade_${selectedCity}_${startDate}_${endDate}`);
  };

  return (
    <div className="flex flex-col gap-4">
       {/* Header / Filters similar to Image 2 */}
       <div className="flex flex-col md:flex-row gap-0 border border-gray-400">

        {/* Left Side: City Selector and Population */}
        <div className="flex-1 bg-white">
          <div className="flex items-center bg-blue-900 text-white p-1 px-2 border-b border-white">
            <span className="font-bold w-24">Cidades</span>
            <select 
              value={selectedCity}
              onChange={(e) => setSelectedCity(e.target.value)}
              className="flex-1 bg-blue-800 text-white border-none text-sm p-1 ml-2 cursor-pointer"
            >
              {cities.map(c => <option key={c} value={c}>{c} - SP</option>)}
            </select>
          </div>
          <div className="flex items-center bg-yellow-300 text-black p-1 px-2 font-bold justify-between">
            <span>Habitantes</span>
            <span>{currentCityPop.toLocaleString('pt-BR')}</span>
          </div>
        </div>

        {/* Right Side: Date Range */}
        <div className="w-full md:w-64 bg-gray-100 p-2 flex flex-col justify-center text-sm border-l border-gray-400">
          <div className="font-bold text-center mb-1">Periodo da Analise</div>
          <div className="flex justify-between items-center mb-1">
            <span className="font-bold mr-2">De:</span>
            <input 
              type="date" 
              value={startDate} 
              onChange={(e) => setStartDate(e.target.value)}
              className="w-32 px-1 border border-gray-300"
            />
          </div>
          <div className="flex justify-between items-center">
            <span className="font-bold mr-2">Até:</span>
            <input 
              type="date" 
              value={endDate} 
              onChange={(e) => setEndDate(e.target.value)}
              className="w-32 px-1 border border-gray-300"
            />
          </div>
        </div>
      </div>

      <div className="flex justify-end">
         <button 
            onClick={handleExport}
            className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded text-sm font-bold flex items-center gap-2 shadow"
          >
            <i className="fas fa-file-excel"></i> Exportar Dados
          </button>
      </div>

      {/* Table - Image 2 Style */}
      <div className="overflow-x-auto">
