import React, { useState, useRef } from 'react';
import RepresentativeTab from './components/RepresentativeTab';
import CityTab from './components/CityTab';
import { MOCK_DATA } from './services/mockData';
import { ClientRecord, ClientStatus } from './types';

type Tab = 'representative' | 'city';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('representative');
  const [clientData, setClientData] = useState<ClientRecord[]>(MOCK_DATA);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Improved CSV export function for Excel compatibility
  const exportToCSV = (data: any[], filename: string) => {
    if (!data || !data.length) {
      alert("Não há dados para exportar.");
      return;
    }

    const headers = Object.keys(data[0]);
    const csvContent = [
      headers.join(';'), // CSV Header
      ...data.map(row => headers.map(fieldName => {
         let val = row[fieldName];
         if (val === null || val === undefined) val = '';
         val = String(val);
         if (val.includes('"') || val.includes(';')) {
           val = `"${val.replace(/"/g, '""')}"`;
         }
         return val;
      }).join(';')) // CSV Rows
    ].join('\r\n');

    // Add BOM
    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    if (link.download !== undefined) { 
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        link.setAttribute("download", `${filename}.csv`);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    }
  };

  // Download Template Function
  const handleDownloadTemplate = () => {
    const headers = ["Representante", "Cidade", "UF", "População", "Status", "DataUltimaCompra"];
    const exampleRow = ["JOAO SILVA", "BAURU", "SP", "379297", "Ativo", "2023-05-20"];

    const csvContent = [
      headers.join(';'),
      exampleRow.join(';')
    ].join('\r\n');

    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", "modelo_importacao.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Import Data Function
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      const text = e.target?.result as string;
      if (!text) return;

      try {
        const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
        // Assume first line is header
        const dataLines = lines.slice(1);

        const newRecords: ClientRecord[] = dataLines.map((line, index) => {
          // Handle quotes if needed, simple split for now assumes no semicolons in data
          // A robust parser would use regex, but simple split matches our export format
          const cols = line.split(';');

          if (cols.length < 6) return null;

          const statusRaw = cols[4]?.replace(/"/g, '').trim();
          let status = ClientStatus.ACTIVE;
          if (statusRaw === 'Semi-ativo') status = ClientStatus.SEMI_ACTIVE;
          if (statusRaw === 'Inativo') status = ClientStatus.INACTIVE;

          return {
            id: `IMP-${Date.now()}-${index}`,
            representativeName: cols[0]?.replace(/"/g, '').trim() || 'Desconhecido',
            city: cols[1]?.replace(/"/g, '').trim() || 'Desconhecida',
            state: cols[2]?.replace(/"/g, '').trim() || 'UF',
            population: parseInt(cols[3]?.replace(/\D/g, '') || '0', 10),
            status: status,
            lastPurchaseDate: cols[5]?.replace(/"/g, '').trim() || new Date().toISOString().split('T')[0]
          };
        }).filter(r => r !== null) as ClientRecord[];

        if (newRecords.length > 0) {
          setClientData(newRecords);
          alert(`${newRecords.length} registros importados com sucesso!`);
        } else {
          alert('Nenhum registro válido encontrado no arquivo.');
        }

      } catch (err) {
        console.error(err);
        alert('Erro ao processar o arquivo. Verifique se é um CSV válido (separado por ponto e vírgula).');
      }

      // Reset input
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  return (
    <div className="min-h-screen bg-gray-50 p-4 font-sans text-gray-800">
      <div className="max-w-5xl mx-auto bg-white shadow-xl rounded-lg overflow-hidden border border-gray-200">

