            <span className="font-bold w-24">Cidades</span>
            <select 
              value={selectedCity}
              onChange={(e) => setSelectedCity(e.target.value)}
              className="flex-1 bg-blue-800 text-white border-none text-sm p-1 ml-2 cursor-pointer"
            >
              {cities.map(c => <option key={c} value={c}>{c} - SP</option>)}
            </select>
          </div>
          <div className="flex items-center bg-yellow-300 text-black p-1 px-2 font-bold justify-between border-b border-white">
            <span>Habitantes</span>
            <span>{currentCityPop.toLocaleString('pt-BR')}</span>
          </div>
          <div className="flex items-center bg-blue-100 text-blue-900 p-1 px-2 font-bold justify-between">
            <span>Representantes Ativos</span>
            <span>{activeRepsCount}</span>
          </div>
        </div>

        {/* Right Side */}
        <div className="w-full md:w-64 bg-gray-100 p-2 flex flex-col justify-center text-sm border-l border-gray-400">
