                  <td className="p-1 px-2 border-r border-gray-400">{row.representativeName}</td>

                  {/* Active Cell */}
                  <td className="p-1 px-2 text-center border-r border-gray-400 font-bold">
                    {row.active > 0 ? (
                       <button 
                         onClick={() => onDrillDown({ rep: row.representativeName, city: selectedCity, status: ClientStatus.ACTIVE })}
                         className="hover:underline text-green-900"
                       >
                         {row.active}
                       </button>
                    ) : ''}
                  </td>

                  {/* Semi-Active Cell */}
                  <td className="p-1 px-2 text-center border-r border-gray-400 font-bold">
                    {row.semiActive > 0 ? (
                       <button 
                        onClick={() => onDrillDown({ rep: row.representativeName, city: selectedCity, status: ClientStatus.SEMI_ACTIVE })}
                        className="hover:underline text-orange-900"
                       >
                         {row.semiActive}
                       </button>
                    ) : ''}
                  </td>

                  {/* Inactive Cell */}
                  <td className="p-1 px-2 text-center border-r border-gray-400 font-bold">
                    {row.inactive > 0 ? (
                       <button 
                        onClick={() => onDrillDown({ rep: row.representativeName, city: selectedCity, status: ClientStatus.INACTIVE })}
                        className="hover:underline text-red-900"
                       >
                         {row.inactive}
                       </button>
                    ) : ''}
                  </td>

                  <td className="p-1 px-2 text-center">{row.total}</td>
                </tr>
              ))
            )}
          </tbody>
          <tfoot>
            <tr className="text-white font-bold text-center">
              <td className="bg-blue-900 text-left p-1 px-2">Total Geral</td>
              <td className="bg-green-500 p-1">{totals.active}</td>
              <td className="bg-orange-500 p-1">{totals.semi}</td>
              <td className="bg-red-700 p-1">{totals.inactive}</td>
              <td className="bg-black p-1">{totals.total}</td>
            </tr>
          </tfoot>
        </table>
      </div>
    </div>
  );
};

