import React, { useState, useMemo } from 'react';
import { ClientRecord, CityViewRow, ClientStatus } from '../types';

interface SupervisorTabProps {
  data: ClientRecord[];
  onExport: (data: any[], filename: string) => void;
  onDrillDown: (filters: { rep?: string; city?: string; status?: ClientStatus; supervisor?: string }) => void;
}

const SupervisorTab: React.FC<SupervisorTabProps> = ({ data, onExport, onDrillDown }) => {
  const [selectedSupervisor, setSelectedSupervisor] = useState<string>('');
  const [startDate, setStartDate] = useState('2022-01-01');
  const [endDate, setEndDate] = useState(new Date().toISOString().split('T')[0]);

  // Extract unique Supervisors
  const supervisors = useMemo(() => 
    Array.from(new Set(data.map(d => d.supervisor))).sort(),
  [data]);

  // Set default supervisor
  React.useEffect(() => {
    if ((!selectedSupervisor || !supervisors.includes(selectedSupervisor)) && supervisors.length > 0) {
      setSelectedSupervisor(supervisors[0]);
    }
  }, [supervisors, selectedSupervisor]);

  // Filter and Aggregate Data
  const tableData = useMemo(() => {
    if (!selectedSupervisor) return [];

    // 1. Filter by Supervisor and Date
    const filtered = data.filter(item => {
      const matchSup = item.supervisor === selectedSupervisor;
      const matchDate = item.lastPurchaseDate >= startDate && item.lastPurchaseDate <= endDate;
      return matchSup && matchDate;
    });

    // 2. Group by Representative
    const repMap = new Map<string, CityViewRow>();

    filtered.forEach(item => {
      if (!repMap.has(item.representativeName)) {
        repMap.set(item.representativeName, {
          representativeName: item.representativeName,
          active: 0,
          semiActive: 0,
          inactive: 0,
          total: 0
        });
      }
      const entry = repMap.get(item.representativeName)!;

      if (item.status === ClientStatus.ACTIVE) entry.active++;
      else if (item.status === ClientStatus.SEMI_ACTIVE) entry.semiActive++;
      else if (item.status === ClientStatus.INACTIVE) entry.inactive++;

      entry.total++;
    });

    return Array.from(repMap.values()).sort((a, b) => a.representativeName.localeCompare(b.representativeName));
  }, [selectedSupervisor, startDate, endDate, data]);

  // Totals
  const totals = tableData.reduce((acc, curr) => ({
    active: acc.active + curr.active,
    semi: acc.semi + curr.semiActive,
    inactive: acc.inactive + curr.inactive,
    total: acc.total + curr.total
  }), { active: 0, semi: 0, inactive: 0, total: 0 });

  const activeRepsCount = tableData.length;

  const handleExport = () => {
    const csvData = tableData.map(row => ({
      'Supervisor': selectedSupervisor,
      'Representante': row.representativeName,
      'Ativo': row.active,
      'Semi-ativo': row.semiActive,
      'Inativo': row.inactive,
      'Total Geral': row.total
    }));
    onExport(csvData, `Status_Supervisor_${selectedSupervisor}_${startDate}_${endDate}`);
  };

  return (
    <div className="flex flex-col gap-4">
       {/* Header / Filters */}
       <div className="flex flex-col md:flex-row gap-0 border border-gray-400">

        {/* Left Side */}
        <div className="flex-1 bg-white flex flex-col">
          <div className="flex items-center bg-blue-900 text-white p-1 px-2 border-b border-white">
            <span className="font-bold w-32">Setor / Sup.</span>
            <select 
              value={selectedSupervisor}
              onChange={(e) => setSelectedSupervisor(e.target.value)}
              className="flex-1 bg-blue-800 text-white border-none text-sm p-1 ml-2 cursor-pointer uppercase"
            >
              {supervisors.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
          <div className="flex items-center bg-yellow-300 text-black p-1 px-2 font-bold justify-between border-b border-white">
            <span>Total Clientes (Filtro)</span>
            <span>{totals.total}</span>
          </div>
          <div className="flex items-center bg-blue-100 text-blue-900 p-1 px-2 font-bold justify-between">
            <span>Representantes no Setor</span>
            <span>{activeRepsCount}</span>
          </div>
        </div>

        {/* Right Side */}
        <div className="w-full md:w-64 bg-gray-100 p-2 flex flex-col justify-center text-sm border-l border-gray-400">
          <div className="font-bold text-center mb-1">Periodo da Analise</div>
          <div className="flex justify-between items-center mb-1">
            <span className="font-bold mr-2">De:</span>
            <input 
              type="date" 
              value={startDate} 
              onChange={(e) => setStartDate(e.target.value)}
              className="w-32 px-1 border border-gray-300"
            />
          </div>
          <div className="flex justify-between items-center">
            <span className="font-bold mr-2">Até:</span>
            <input 
              type="date" 
              value={endDate} 
              onChange={(e) => setEndDate(e.target.value)}
              className="w-32 px-1 border border-gray-300"
            />
          </div>
        </div>
      </div>

      <div className="flex justify-end">
         <button 
            onClick={handleExport}
            className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded text-sm font-bold flex items-center gap-2 shadow"
          >
            <i className="fas fa-file-excel"></i> Exportar Dados
          </button>
      </div>

      {/* Table */}
      <div className="overflow-x-auto">
        <table className="w-full text-sm font-sans border-collapse">
          <thead>
            <tr className="text-white">
              <th className="bg-blue-900 text-left p-1 pl-2 border-r border-white w-1/3">Representante</th>
              <th className="bg-green-500 text-center p-1 border-r border-white">Ativo</th>
              <th className="bg-orange-400 text-center p-1 border-r border-white">Semi-ativo</th>
              <th className="bg-red-600 text-center p-1 border-r border-white">Inativo</th>
              <th className="bg-black text-center p-1">Total Geral</th>
            </tr>
          </thead>
          <tbody>
            {tableData.length === 0 ? (
               <tr><td colSpan={5} className="p-4 text-center text-gray-500 bg-blue-50">Nenhum dado para este período</td></tr>
            ) : (
              tableData.map((row, idx) => (
                <tr key={idx} className="bg-blue-200 border-b border-blue-300 hover:bg-blue-300 transition-colors text-black">
                  <td className="p-1 px-2 border-r border-gray-400">{row.representativeName}</td>

                  {/* Active Cell */}
