            <i className="fas fa-user-shield mr-2"></i>
            Supervisor
          </button>
        </div>

        {/* Content Area */}
        <div className="p-6 md:p-8 bg-white min-h-[500px]">
          {activeTab === 'representative' ? (
            <RepresentativeTab 
              data={clientData} 
              onExport={exportToCSV} 
              onDrillDown={handleDrillDown} 
            />
          ) : activeTab === 'city' ? (
            <CityTab 
              data={clientData} 
              onExport={exportToCSV}
              onDrillDown={handleDrillDown}
            />
          ) : (
            <SupervisorTab 
              data={clientData} 
              onExport={exportToCSV}
              onDrillDown={handleDrillDown}
            />
          )}
        </div>

        <div className="bg-gray-50 p-4 text-center text-xs text-gray-400 border-t border-gray-100">
          &copy; {new Date().getFullYear()} Millenium Utilidades Domesticas LTDA. Todos os direitos reservados.
        </div>
      </div>

      {/* Drill Down Modal */}
      <ClientListModal 
        isOpen={modalOpen}
        onClose={() => setModalOpen(false)}
        title={modalTitle}
        clients={modalClients}
      />
    </div>
  );
};

