import React, { useState, useMemo } from 'react';
import { ClientRecord, RepViewRow, ClientStatus } from '../types';

interface RepresentativeTabProps {
  data: ClientRecord[];
  onExport: (data: any[], filename: string) => void;
  onDrillDown: (filters: { rep?: string; city?: string; status?: ClientStatus }) => void;
}

const RepresentativeTab: React.FC<RepresentativeTabProps> = ({ data, onExport, onDrillDown }) => {
  const [selectedRep, setSelectedRep] = useState<string>('');
  const [startDate, setStartDate] = useState('2023-01-01');
  const [endDate, setEndDate] = useState(new Date().toISOString().split('T')[0]);

  // Extract unique reps
  const representatives = useMemo(() => {
    const reps = Array.from(new Set(data.map(d => d.representativeName))).sort();
    return reps;
  }, [data]);

  // Set default selected rep
  React.useEffect(() => {
    if ((!selectedRep || !representatives.includes(selectedRep)) && representatives.length > 0) {
      setSelectedRep(representatives[0]);
    }
  }, [representatives, selectedRep]);

  // Filter and Aggregate Data
  const tableData = useMemo(() => {
    if (!selectedRep) return [];

    // 1. Filter by Rep and Date
    const filtered = data.filter(item => {
      const matchRep = item.representativeName === selectedRep;
      const matchDate = item.lastPurchaseDate >= startDate && item.lastPurchaseDate <= endDate;
      const isPositive = item.status === ClientStatus.ACTIVE; 
      return matchRep && matchDate && isPositive;
    });

    // 2. Group by City
    const cityMap = new Map<string, RepViewRow>();

    filtered.forEach(item => {
      const key = `${item.city} - ${item.state}`;
      if (!cityMap.has(key)) {
        cityMap.set(key, {
          city: item.city,
          state: item.state,
          positiveCount: 0,
          population: item.population
        });
      }
      const entry = cityMap.get(key)!;
      entry.positiveCount += 1;
    });

    return Array.from(cityMap.values()).sort((a, b) => a.city.localeCompare(b.city));
  }, [data, selectedRep, startDate, endDate]);

  const totalPositivated = tableData.reduce((acc, curr) => acc + curr.positiveCount, 0);
  const totalPop = tableData.reduce((acc, curr) => acc + curr.population, 0);

  const handleExport = () => {
    const csvData = tableData.map(row => ({
      'Cidade/UF': `${row.city} - ${row.state}`,
      'Positivação': row.positiveCount,
      'Habitantes': row.population
    }));
    onExport(csvData, `Positivacao_${selectedRep}_${startDate}_${endDate}`);
  };

  return (
    <div className="flex flex-col gap-6">
      {/* Header / Filters */}
      <div className="bg-yellow-50 p-4 border border-yellow-200 shadow-sm rounded-2xl">
        <h2 className="text-xl font-bold text-blue-900 mb-4 text-center uppercase tracking-wide">
          Análise por Representante
        </h2>

        <div className="flex flex-wrap lg:flex-nowrap justify-between items-end gap-4 bg-white p-4 rounded-xl shadow-inner border border-yellow-100">
          <div className="w-full lg:w-1/3">
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1 ml-1">Selecione o Representante</label>
            <div className="relative">
              <select 
                value={selectedRep}
                onChange={(e) => setSelectedRep(e.target.value)}
                className="w-full p-2.5 pl-3 border border-gray-300 bg-gray-50 rounded-lg text-sm text-gray-700 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all appearance-none"
              >
                {representatives.map(r => <option key={r} value={r}>{r}</option>)}
              </select>
              <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-gray-700">
                <i className="fas fa-chevron-down text-xs"></i>
              </div>
            </div>
          </div>

          <div className="flex flex-wrap sm:flex-nowrap gap-4 items-center w-full lg:w-auto">
            <div className="flex flex-col">
              <label className="text-xs font-bold text-gray-500 uppercase mb-1 ml-1">Período</label>
              <div className="flex gap-2 items-center">
                 <input 
                  type="date" 
                  value={startDate} 
                  onChange={(e) => setStartDate(e.target.value)}
                  className="border border-gray-300 bg-gray-50 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                />
                <span className="text-gray-400 font-bold">-</span>
                <input 
                  type="date" 
                  value={endDate} 
                  onChange={(e) => setEndDate(e.target.value)}
                  className="border border-gray-300 bg-gray-50 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
            </div>

            <button 
              onClick={handleExport}
              className="mt-5 bg-green-600 hover:bg-green-700 text-white px-6 py-2.5 rounded-full text-sm font-bold flex items-center gap-2 shadow-md hover:shadow-lg transition-all"
            >
              <i className="fas fa-file-excel"></i> Exportar
            </button>
          </div>
        </div>
      </div>

      {/* Table */}
      <div className="overflow-hidden border border-gray-200 rounded-2xl shadow-lg">
        <table className="w-full text-sm font-sans">
          <thead>
            <tr className="bg-gradient-to-r from-gray-900 to-gray-800 text-white">
              <th className="text-left p-4 font-semibold">Cidades/UF</th>
              <th className="text-right p-4 font-semibold">Positivação</th>
              <th className="text-right p-4 font-semibold">Habitantes</th>
            </tr>
          </thead>
          <tbody>
            {tableData.length === 0 ? (
              <tr><td colSpan={3} className="p-8 text-center text-gray-500 bg-gray-50">Nenhum dado encontrado</td></tr>
            ) : (
              tableData.map((row, idx) => (
                <tr key={idx} className={`transition-colors border-b border-gray-100 ${idx % 2 === 0 ? "bg-white" : "bg-blue-50/30"} hover:bg-blue-50`}>
                  <td className="p-3 px-4 font-medium text-gray-800">
                    {row.city} - {row.state}
                  </td>
                  <td className="p-3 px-4 text-right">
                    <button 
                      onClick={() => onDrillDown({ 
                        rep: selectedRep, 
                        city: row.city,
                        status: ClientStatus.ACTIVE 
                      })}
                      className="inline-flex items-center justify-center min-w-[30px] h-[30px] rounded-full bg-blue-100 text-blue-800 font-bold text-xs hover:bg-blue-200 transition-colors"
                    >
                      {row.positiveCount}
                    </button>
                  </td>
                  <td className="p-3 px-4 text-right text-gray-600">
                    {row.population.toLocaleString('pt-BR')}
                  </td>
                </tr>
              ))
            )}
          </tbody>
          <tfoot>
            <tr className="bg-gray-100 text-gray-800 font-bold border-t-2 border-gray-300">
              <td className="p-4">Total Geral</td>
              <td className="p-4 text-right text-blue-900">{totalPositivated}</td>
              <td className="p-4 text-right">{totalPop.toLocaleString('pt-BR')}</td>
            </tr>
          </tfoot>
        </table>
      </div>
    </div>
  );
};

