          </tbody>
          <tfoot>
            <tr className="text-white font-bold text-center">
              <td className="bg-blue-900 text-left p-4">Total Geral</td>
              <td className="bg-green-600 p-4">{totals.active}</td>
              <td className="bg-orange-500 p-4">{totals.semi}</td>
              <td className="bg-red-700 p-4">{totals.inactive}</td>
