              />
            </div>
          </div>

          <button 
            onClick={handleExport}
            className="mt-6 bg-green-600 hover:bg-green-700 text-white w-full py-3 rounded-xl text-sm font-bold flex justify-center items-center gap-2 shadow-md hover:shadow-lg transition-all"
          >
            <i className="fas fa-file-excel"></i> Exportar Dados
          </button>
        </div>
      </div>

      {/* Table */}
      <div className="overflow-hidden rounded-2xl shadow-lg border border-gray-200">
        <table className="w-full text-sm font-sans border-collapse">
          <thead>
            <tr className="text-white">
              <th className="bg-blue-900 text-left p-4 w-1/3">Representante (Rep 3)</th>
              <th className="bg-green-600 text-center p-4">Ativo</th>
              <th className="bg-orange-400 text-center p-4">Semi-ativo</th>
              <th className="bg-red-600 text-center p-4">Inativo</th>
              <th className="bg-gray-900 text-center p-4">Total Geral</th>
            </tr>
          </thead>
          <tbody>
            {tableData.length === 0 ? (
               <tr><td colSpan={5} className="p-8 text-center text-gray-500 bg-gray-50">Nenhum dado para este período</td></tr>
            ) : (
              tableData.map((row, idx) => (
                <tr key={idx} className="bg-white border-b border-gray-100 hover:bg-blue-50 transition-colors text-gray-800">
                  <td className="p-3 px-4 font-medium border-r border-gray-100">{row.representativeName}</td>

                  {/* Active Cell */}
                  <td className="p-3 px-4 text-center border-r border-gray-100">
                    {row.active > 0 ? (
                       <button 
                         onClick={() => onDrillDown({ rep: row.representativeName, supervisor: selectedSupervisor, status: ClientStatus.ACTIVE })}
                         className="px-3 py-1 rounded-full bg-green-100 text-green-800 font-bold text-xs hover:bg-green-200 transition-colors"
                       >
                         {row.active}
                       </button>
                    ) : <span className="text-gray-300">-</span>}
                  </td>

                  {/* Semi-Active Cell */}
                  <td className="p-3 px-4 text-center border-r border-gray-100">
                    {row.semiActive > 0 ? (
                       <button 
                        onClick={() => onDrillDown({ rep: row.representativeName, supervisor: selectedSupervisor, status: ClientStatus.SEMI_ACTIVE })}
                        className="px-3 py-1 rounded-full bg-orange-100 text-orange-800 font-bold text-xs hover:bg-orange-200 transition-colors"
                       >
                         {row.semiActive}
                       </button>
                    ) : <span className="text-gray-300">-</span>}
                  </td>

                  {/* Inactive Cell */}
                  <td className="p-3 px-4 text-center border-r border-gray-100">
                    {row.inactive > 0 ? (
                       <button 
                        onClick={() => onDrillDown({ rep: row.representativeName, supervisor: selectedSupervisor, status: ClientStatus.INACTIVE })}
                        className="px-3 py-1 rounded-full bg-red-100 text-red-800 font-bold text-xs hover:bg-red-200 transition-colors"
                       >
