import React, { useState, useMemo, useRef, useEffect } from 'react';
import { ClientRecord, RepViewRow, ClientStatus } from '../types';

interface RepresentativeTabProps {
  data: ClientRecord[];
  onExport: (data: any[], filename: string) => void;
  onDrillDown: (filters: { rep?: string; city?: string; status?: ClientStatus | ClientStatus[] }) => void;
}

const RepresentativeTab: React.FC<RepresentativeTabProps> = ({ data, onExport, onDrillDown }) => {
  const [selectedRep, setSelectedRep] = useState<string>('');
  const [startDate, setStartDate] = useState('2023-01-01');
  const [endDate, setEndDate] = useState(new Date().toISOString().split('T')[0]);

  // Searchable Select States
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Extract unique reps from rep3 column
  const representatives = useMemo(() => {
    const reps = Array.from(new Set(data.map(d => d.rep3))).sort();
    return reps;
  }, [data]);

  // Set default selected rep
  useEffect(() => {
    if ((!selectedRep || !representatives.includes(selectedRep)) && representatives.length > 0) {
      const initial = representatives[0];
      setSelectedRep(initial);
      setSearchTerm(initial);
    }
  }, [representatives, selectedRep]);

  // Handle clicking outside to close dropdown
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsDropdownOpen(false);
        // If user typed something invalid and clicked out, revert to selectedRep
        if (!representatives.includes(searchTerm) && searchTerm !== '') {
           setSearchTerm(selectedRep);
        } else if (searchTerm === '') {
           // If cleared and clicked out, revert or keep cleared? 
           // Better to revert to ensure data is shown, or keep empty if allowed.
           // For this app, let's revert to ensure a valid state.
           setSearchTerm(selectedRep);
        }
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [dropdownRef, selectedRep, searchTerm, representatives]);

  // Filtered Options for the Dropdown
  const filteredOptions = useMemo(() => {
    if (!searchTerm) return representatives;
    return representatives.filter(r => 
      r.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [representatives, searchTerm]);

  const handleSelectRep = (rep: string) => {
    setSelectedRep(rep);
    setSearchTerm(rep);
    setIsDropdownOpen(false);
  };

  // Filter and Aggregate Data
  const tableData = useMemo(() => {
    if (!selectedRep) return [];

    // 1. Filter by Rep3 and Date
    const filtered = data.filter(item => {
      const matchRep = item.rep3 === selectedRep; // Using rep3
      const matchDate = item.lastPurchaseDate >= startDate && item.lastPurchaseDate <= endDate;
      // Filter now includes both ACTIVE and SEMI_ACTIVE
      const isPositive = item.status === ClientStatus.ACTIVE || item.status === ClientStatus.SEMI_ACTIVE; 
      return matchRep && matchDate && isPositive;
    });

    // 2. Group by City
    const cityMap = new Map<string, RepViewRow>();

    filtered.forEach(item => {
      const key = `${item.city} - ${item.state}`;
      if (!cityMap.has(key)) {
        cityMap.set(key, {
          city: item.city,
          state: item.state,
          positiveCount: 0,
          population: item.population
        });
      }
      const entry = cityMap.get(key)!;
      entry.positiveCount += 1;
    });

    return Array.from(cityMap.values()).sort((a, b) => a.city.localeCompare(b.city));
  }, [data, selectedRep, startDate, endDate]);

  const totalPositivated = tableData.reduce((acc, curr) => acc + curr.positiveCount, 0);
  const totalPop = tableData.reduce((acc, curr) => acc + curr.population, 0);

  const handleExport = () => {
    const csvData = tableData.map(row => ({
      'Cidade/UF': `${row.city} - ${row.state}`,
      'Positivação (Ativos + Semi)': row.positiveCount,
      'Habitantes': row.population
    }));
    onExport(csvData, `Positivacao_${selectedRep}_${startDate}_${endDate}`);
  };

  return (
    <div className="flex flex-col gap-6">
      {/* Header / Filters */}
      <div className="bg-yellow-50 p-4 border border-yellow-200 shadow-sm rounded-2xl">

        <div className="flex flex-col lg:flex-row justify-between items-end gap-4 bg-white p-4 rounded-xl shadow-inner border border-yellow-100">

          {/* SEARCHABLE REPRESENTATIVE INPUT */}
          <div className="w-full lg:w-1/3 relative" ref={dropdownRef}>
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1 ml-1">Selecione o Representante</label>
            <div className="relative group">
              <input 
                type="text"
                value={searchTerm}
                onChange={(e) => {
                  setSearchTerm(e.target.value);
                  setIsDropdownOpen(true);
                }}
                onClick={() => setIsDropdownOpen(true)}
                placeholder="Digite para buscar..."
                className="w-full p-2.5 pl-3 pr-10 border border-gray-300 bg-gray-50 rounded-lg text-sm text-gray-700 font-semibold focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all shadow-sm"
              />
              <div 
                className="absolute inset-y-0 right-0 flex items-center px-3 cursor-pointer text-gray-500 hover:text-blue-600"
                onClick={() => setIsDropdownOpen(!isDropdownOpen)}
              >
                <i className={`fas fa-chevron-down text-xs transition-transform duration-200 ${isDropdownOpen ? 'transform rotate-180' : ''}`}></i>
              </div>
            </div>

            {/* DROPDOWN LIST */}
            {isDropdownOpen && (
              <ul className="absolute z-50 w-full mt-1 bg-white border border-gray-200 rounded-lg shadow-xl max-h-60 overflow-y-auto animate-fade-in">
                {filteredOptions.length === 0 ? (
                  <li className="p-3 text-sm text-gray-400 text-center italic">Nenhum representante encontrado</li>
                ) : (
                  filteredOptions.map((rep) => (
                    <li 
                      key={rep}
                      onClick={() => handleSelectRep(rep)}
                      className={`px-4 py-2 text-sm cursor-pointer hover:bg-blue-50 hover:text-blue-700 transition-colors border-b border-gray-50 last:border-none ${rep === selectedRep ? 'bg-blue-100 text-blue-900 font-bold' : 'text-gray-700'}`}
                    >
                      {rep}
                    </li>
                  ))
                )}
              </ul>
            )}
          </div>

          <div className="flex flex-col sm:flex-row gap-4 items-end w-full lg:w-auto">
            <div className="flex flex-col w-full sm:w-auto">
              <label className="text-xs font-bold text-gray-500 uppercase mb-1 ml-1">Período</label>
              <div className="flex flex-col sm:flex-row gap-2 items-center">
                 <input 
                  type="date" 
                  value={startDate} 
                  onChange={(e) => setStartDate(e.target.value)}
                  className="w-full sm:w-auto border border-gray-300 bg-gray-50 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                />
                <span className="hidden sm:inline text-gray-400 font-bold">-</span>
                <span className="sm:hidden text-gray-400 font-bold text-xs my-1">até</span>
                <input 
                  type="date" 
                  value={endDate} 
                  onChange={(e) => setEndDate(e.target.value)}
                  className="w-full sm:w-auto border border-gray-300 bg-gray-50 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
            </div>

            <button 
              onClick={handleExport}
              className="w-full sm:w-auto bg-green-600 hover:bg-green-700 text-white px-6 py-2.5 rounded-full text-sm font-bold flex justify-center items-center gap-2 shadow-md hover:shadow-lg transition-all"
            >
              <i className="fas fa-file-excel"></i> Exportar
            </button>
          </div>
        </div>
      </div>

      {/* Table */}
      <div className="overflow-hidden border border-gray-200 rounded-2xl shadow-lg">
        <table className="w-full text-sm font-sans">
          <thead>
            <tr className="bg-gradient-to-r from-gray-900 to-gray-800 text-white">
              <th className="text-left p-4 font-semibold">Cidades/UF</th>
              <th className="text-right p-4 font-semibold">Positivação (Ativo + Semi)</th>
              <th className="text-right p-4 font-semibold">Habitantes</th>
            </tr>
          </thead>
          <tbody>
            {tableData.length === 0 ? (
              <tr><td colSpan={3} className="p-8 text-center text-gray-500 bg-gray-50">Nenhum dado encontrado</td></tr>
            ) : (
              tableData.map((row, idx) => (
                <tr key={idx} className={`transition-colors border-b border-gray-100 ${idx % 2 === 0 ? "bg-white" : "bg-blue-50/30"} hover:bg-blue-50`}>
                  <td className="p-3 px-4 font-medium text-gray-800">
                    {row.city} - {row.state}
                  </td>
                  <td className="p-3 px-4 text-right">
                    <button 
                      onClick={() => onDrillDown({ 
                        rep: selectedRep, 
                        city: row.city,
                        status: [ClientStatus.ACTIVE, ClientStatus.SEMI_ACTIVE] // Pass array for both
                      })}
                      className="inline-flex items-center justify-center min-w-[30px] h-[30px] rounded-full bg-blue-100 text-blue-800 font-bold text-xs hover:bg-blue-200 transition-colors"
                    >
                      {row.positiveCount}
                    </button>
                  </td>
                  <td className="p-3 px-4 text-right text-gray-600">
                    {row.population.toLocaleString('pt-BR')}
                  </td>
                </tr>
              ))
            )}
          </tbody>
          <tfoot>
            <tr className="bg-gray-100 text-gray-800 font-bold border-t-2 border-gray-300">
              <td className="p-4">Total Geral</td>
              <td className="p-4 text-right">
                <button 
                  onClick={() => onDrillDown({ 
                      rep: selectedRep, 
                      status: [ClientStatus.ACTIVE, ClientStatus.SEMI_ACTIVE] 
                  })}
                  className="px-3 py-1 rounded-full bg-blue-200 text-blue-900 hover:bg-blue-300 transition-colors"
                >
                  {totalPositivated}
                </button>
              </td>
              <td className="p-4 text-right">{totalPop.toLocaleString('pt-BR')}</td>
            </tr>
          </tfoot>
        </table>
      </div>
    </div>
  );
};

export default RepresentativeTab;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { ClientRecord, CityViewRow, ClientStatus } from '../types';

interface CityTabProps {
  data: ClientRecord[];
  onExport: (data: any[], filename: string) => void;
  onDrillDown: (filters: { rep?: string; city?: string; status?: ClientStatus | ClientStatus[] }) => void;
}

const CityTab: React.FC<CityTabProps> = ({ data, onExport, onDrillDown }) => {
  const [selectedCity, setSelectedCity] = useState<string>('');
  const [startDate, setStartDate] = useState('2022-01-01');
  const [endDate, setEndDate] = useState(new Date().toISOString().split('T')[0]);

  // Searchable Select States
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Extract unique cities
  const cities = useMemo(() => 
    Array.from(new Set(data.map(d => d.city))).sort(),
  [data]);

  // Set default city if empty
  useEffect(() => {
    if ((!selectedCity || !cities.includes(selectedCity)) && cities.length > 0) {
      let initial = cities[0];
      if (cities.includes('BAURU')) initial = 'BAURU';

      setSelectedCity(initial);
      setSearchTerm(initial);
    }
  }, [cities, selectedCity]);

  // Handle clicking outside to close dropdown
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsDropdownOpen(false);
        // Revert to selectedCity if invalid
        if (!cities.includes(searchTerm) && searchTerm !== '') {
           setSearchTerm(selectedCity);
        } else if (searchTerm === '') {
           setSearchTerm(selectedCity);
        }
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [dropdownRef, selectedCity, searchTerm, cities]);

  // Filtered Options
  const filteredOptions = useMemo(() => {
    if (!searchTerm) return cities;
    return cities.filter(c => 
      c.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [cities, searchTerm]);

  const handleSelectCity = (city: string) => {
    setSelectedCity(city);
    setSearchTerm(city);
    setIsDropdownOpen(false);
  };

  // Get current city population
  const currentCityPop = useMemo(() => {
    const record = data.find(d => d.city === selectedCity);
    return record ? record.population : 0;
  }, [selectedCity, data]);

  // Filter and Aggregate Data
  const tableData = useMemo(() => {
    if (!selectedCity) return [];

    // 1. Filter by City and Date
    const filtered = data.filter(item => {
      const matchCity = item.city === selectedCity;
      const matchDate = item.lastPurchaseDate >= startDate && item.lastPurchaseDate <= endDate;
      return matchCity && matchDate;
    });

    // 2. Group by Representative (Using rep3 now)
    const repMap = new Map<string, CityViewRow>();

    filtered.forEach(item => {
      // Use rep3 for grouping
      const repKey = item.rep3;

      if (!repMap.has(repKey)) {
        repMap.set(repKey, {
          representativeName: repKey,
          active: 0,
          semiActive: 0,
          inactive: 0,
          total: 0
        });
      }
      const entry = repMap.get(repKey)!;

      if (item.status === ClientStatus.ACTIVE) entry.active++;
      else if (item.status === ClientStatus.SEMI_ACTIVE) entry.semiActive++;
      else if (item.status === ClientStatus.INACTIVE) entry.inactive++;

      entry.total++;
    });

    return Array.from(repMap.values()).sort((a, b) => a.representativeName.localeCompare(b.representativeName));
  }, [selectedCity, startDate, endDate, data]);

  // Totals
  const totals = tableData.reduce((acc, curr) => ({
    active: acc.active + curr.active,
    semi: acc.semi + curr.semiActive,
    inactive: acc.inactive + curr.inactive,
    total: acc.total + curr.total
  }), { active: 0, semi: 0, inactive: 0, total: 0 });

  const activeRepsCount = tableData.length;

  const handleExport = () => {
    const csvData = tableData.map(row => ({
      'Representante': row.representativeName,
      'Ativo': row.active,
      'Semi-ativo': row.semiActive,
      'Inativo': row.inactive,
      'Total Geral': row.total
    }));
    onExport(csvData, `Status_Cidade_${selectedCity}_${startDate}_${endDate}`);
  };

  return (
    <div className="flex flex-col gap-6">
       {/* Header / Filters Container */}
       <div className="flex flex-col md:flex-row gap-0 border border-gray-200 shadow-lg rounded-2xl overflow-hidden">

        {/* Left Side: Info Panel */}
        <div className="flex-1 flex flex-col">
          {/* City Select - Searchable */}
          <div className="flex items-center bg-blue-900 text-white p-4 relative" ref={dropdownRef}>
            <span className="font-bold w-20 text-blue-200 shrink-0">Cidade</span>
            <div className="flex-1 relative group">
              <input 
                type="text"
                value={searchTerm}
                onChange={(e) => {
                  setSearchTerm(e.target.value);
                  setIsDropdownOpen(true);
                }}
                onClick={() => setIsDropdownOpen(true)}
                placeholder="Buscar cidade..."
                className="w-full bg-blue-800/50 text-white border border-blue-700 rounded-lg text-sm p-2 pr-8 focus:outline-none focus:ring-2 focus:ring-blue-400 placeholder-blue-300 font-bold uppercase"
              />
               <div 
                className="absolute inset-y-0 right-0 flex items-center px-2 cursor-pointer text-blue-300 hover:text-white"
                onClick={() => setIsDropdownOpen(!isDropdownOpen)}
              >
                <i className={`fas fa-chevron-down text-xs transition-transform duration-200 ${isDropdownOpen ? 'transform rotate-180' : ''}`}></i>
              </div>

              {/* Dropdown List */}
              {isDropdownOpen && (
                <ul className="absolute left-0 top-full mt-1 w-full bg-white text-gray-800 rounded-lg shadow-xl max-h-60 overflow-y-auto z-50 animate-fade-in border border-gray-200">
                   {filteredOptions.length === 0 ? (
                    <li className="p-3 text-sm text-gray-400 text-center italic">Nenhuma cidade encontrada</li>
                  ) : (
                    filteredOptions.map((city) => (
                      <li 
                        key={city}
                        onClick={() => handleSelectCity(city)}
                        className={`px-4 py-2 text-sm cursor-pointer hover:bg-blue-50 hover:text-blue-700 transition-colors border-b border-gray-50 last:border-none uppercase ${city === selectedCity ? 'bg-blue-100 text-blue-900 font-bold' : ''}`}
                      >
                        {city} - SP
                      </li>
                    ))
                  )}
                </ul>
              )}
            </div>
          </div>

          <div className="flex-1 flex flex-col justify-center">
            <div className="flex items-center bg-yellow-400 text-blue-900 p-3 px-6 font-bold justify-between border-b border-yellow-300/50">
              <span className="uppercase text-xs opacity-80">Habitantes</span>
              <span className="text-xl">{currentCityPop.toLocaleString('pt-BR')}</span>
            </div>
            <div className="flex items-center bg-blue-50 text-blue-900 p-3 px-6 font-bold justify-between">
              <span className="uppercase text-xs opacity-70">Representantes Ativos</span>
              <span className="text-lg">{activeRepsCount}</span>
            </div>
          </div>
        </div>

        {/* Right Side: Date & Actions */}
        <div className="w-full md:w-80 bg-gray-50 p-6 flex flex-col justify-center border-l border-gray-200">
          <div className="font-bold text-center mb-4 text-gray-500 uppercase text-xs tracking-wider">Período da Análise</div>

          <div className="space-y-3">
            <div className="flex justify-between items-center bg-white p-2 rounded-lg border border-gray-200 shadow-sm">
              <span className="font-bold text-gray-400 text-xs px-2">DE</span>
              <input 
                type="date" 
                value={startDate} 
                onChange={(e) => setStartDate(e.target.value)}
                className="text-right text-sm font-semibold text-gray-700 focus:outline-none bg-transparent"
              />
            </div>
            <div className="flex justify-between items-center bg-white p-2 rounded-lg border border-gray-200 shadow-sm">
              <span className="font-bold text-gray-400 text-xs px-2">ATÉ</span>
              <input 
                type="date" 
                value={endDate} 
                onChange={(e) => setEndDate(e.target.value)}
                className="text-right text-sm font-semibold text-gray-700 focus:outline-none bg-transparent"
              />
            </div>
          </div>

          <button 
            onClick={handleExport}
            className="mt-6 bg-green-600 hover:bg-green-700 text-white w-full py-3 rounded-xl text-sm font-bold flex justify-center items-center gap-2 shadow-md hover:shadow-lg transition-all"
          >
            <i className="fas fa-file-excel"></i> Exportar Dados
          </button>
        </div>
      </div>

      {/* Table */}
      <div className="overflow-hidden rounded-2xl shadow-lg border border-gray-200">
        <table className="w-full text-sm font-sans border-collapse">
          <thead>
            <tr className="text-white">
              <th className="bg-blue-900 text-left p-4 w-1/3">Representante (Rep 3)</th>
              <th className="bg-green-600 text-center p-4">Ativo</th>
              <th className="bg-orange-400 text-center p-4">Semi-Ativo</th>
              <th className="bg-red-600 text-center p-4">Inativo</th>
              <th className="bg-gray-900 text-center p-4">Total Geral</th>
            </tr>
          </thead>
          <tbody>
            {tableData.length === 0 ? (
               <tr><td colSpan={5} className="p-8 text-center text-gray-500 bg-gray-50">Nenhum dado para este período</td></tr>
            ) : (
              tableData.map((row, idx) => (
                <tr key={idx} className="bg-white border-b border-gray-100 hover:bg-blue-50 transition-colors text-gray-800">
                  <td className="p-3 px-4 font-medium border-r border-gray-100">{row.representativeName}</td>

                  {/* Active Cell */}
                  <td className="p-3 px-4 text-center border-r border-gray-100">
                    {row.active > 0 ? (
                       <button 
                         onClick={() => onDrillDown({ rep: row.representativeName, city: selectedCity, status: ClientStatus.ACTIVE })}
                         className="px-3 py-1 rounded-full bg-green-100 text-green-800 font-bold text-xs hover:bg-green-200 transition-colors"
                       >
                         {row.active}
                       </button>
                    ) : <span className="text-gray-300">-</span>}
                  </td>

                  {/* Semi-Active Cell */}
                  <td className="p-3 px-4 text-center border-r border-gray-100">
                    {row.semiActive > 0 ? (
                       <button 
                        onClick={() => onDrillDown({ rep: row.representativeName, city: selectedCity, status: ClientStatus.SEMI_ACTIVE })}
                        className="px-3 py-1 rounded-full bg-orange-100 text-orange-800 font-bold text-xs hover:bg-orange-200 transition-colors"
                       >
                         {row.semiActive}
                       </button>
                    ) : <span className="text-gray-300">-</span>}
                  </td>

                  {/* Inactive Cell */}
                  <td className="p-3 px-4 text-center border-r border-gray-100">
                    {row.inactive > 0 ? (
                       <button 
                        onClick={() => onDrillDown({ rep: row.representativeName, city: selectedCity, status: ClientStatus.INACTIVE })}
                        className="px-3 py-1 rounded-full bg-red-100 text-red-800 font-bold text-xs hover:bg-red-200 transition-colors"
                       >
                         {row.inactive}
                       </button>
                    ) : <span className="text-gray-300">-</span>}
                  </td>

                  {/* Total Cell */}
                  <td className="p-3 px-4 text-center font-bold text-gray-700">
                    {row.total > 0 ? (
                        <button 
                          onClick={() => onDrillDown({ rep: row.representativeName, city: selectedCity })}
                          className="px-3 py-1 rounded-full bg-gray-200 text-gray-900 font-bold text-xs hover:bg-gray-300 transition-colors"
                        >
                          {row.total}
                        </button>
                    ) : 0}
                  </td>
                </tr>
              ))
            )}
          </tbody>
          <tfoot>
            <tr className="text-white font-bold text-center">
              <td className="bg-blue-900 text-left p-4">Total Geral</td>
              <td 
                className="bg-green-600 p-4 cursor-pointer hover:bg-green-500 transition-colors"
                onClick={() => onDrillDown({ city: selectedCity, status: ClientStatus.ACTIVE })}
                title="Ver detalhes de Ativos"
              >
                {totals.active}
              </td>
              <td 
                className="bg-orange-500 p-4 cursor-pointer hover:bg-orange-400 transition-colors"
                onClick={() => onDrillDown({ city: selectedCity, status: ClientStatus.SEMI_ACTIVE })}
                title="Ver detalhes de Semi-ativos"
              >
                {totals.semi}
              </td>
              <td 
                className="bg-red-700 p-4 cursor-pointer hover:bg-red-600 transition-colors"
                onClick={() => onDrillDown({ city: selectedCity, status: ClientStatus.INACTIVE })}
                title="Ver detalhes de Inativos"
              >
                {totals.inactive}
              </td>
              <td 
                className="bg-gray-900 p-4 cursor-pointer hover:bg-gray-800 transition-colors"
                onClick={() => onDrillDown({ city: selectedCity })}
                title="Ver detalhes Geral"
              >
                {totals.total}
              </td>
            </tr>
          </tfoot>
        </table>
      </div>
    </div>
  );
};

export default CityTab;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { ClientRecord, CityViewRow, ClientStatus } from '../types';

interface SupervisorTabProps {
  data: ClientRecord[];
  onExport: (data: any[], filename: string) => void;
  onDrillDown: (filters: { rep?: string; city?: string; status?: ClientStatus | ClientStatus[]; supervisor?: string }) => void;
}

const SupervisorTab: React.FC<SupervisorTabProps> = ({ data, onExport, onDrillDown }) => {
  const [selectedSupervisor, setSelectedSupervisor] = useState<string>('');
  const [startDate, setStartDate] = useState('2022-01-01');
  const [endDate, setEndDate] = useState(new Date().toISOString().split('T')[0]);

  // Searchable Select States
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Extract unique Supervisors
  const supervisors = useMemo(() => 
    Array.from(new Set(data.map(d => d.supervisor))).sort(),
  [data]);

  // Set default supervisor
  useEffect(() => {
    if ((!selectedSupervisor || !supervisors.includes(selectedSupervisor)) && supervisors.length > 0) {
      const initial = supervisors[0];
      setSelectedSupervisor(initial);
      setSearchTerm(initial);
    }
  }, [supervisors, selectedSupervisor]);

  // Handle clicking outside to close dropdown
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsDropdownOpen(false);
        // Revert to selectedSupervisor if invalid
        if (!supervisors.includes(searchTerm) && searchTerm !== '') {
           setSearchTerm(selectedSupervisor);
        } else if (searchTerm === '') {
           setSearchTerm(selectedSupervisor);
        }
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [dropdownRef, selectedSupervisor, searchTerm, supervisors]);

  // Filtered Options
  const filteredOptions = useMemo(() => {
    if (!searchTerm) return supervisors;
    return supervisors.filter(s => 
      s.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [supervisors, searchTerm]);

  const handleSelectSupervisor = (sup: string) => {
    setSelectedSupervisor(sup);
    setSearchTerm(sup);
    setIsDropdownOpen(false);
  };

  // Filter and Aggregate Data
  const tableData = useMemo(() => {
    if (!selectedSupervisor) return [];

    // 1. Filter by Supervisor and Date
    const filtered = data.filter(item => {
      const matchSup = item.supervisor === selectedSupervisor;
      const matchDate = item.lastPurchaseDate >= startDate && item.lastPurchaseDate <= endDate;
      return matchSup && matchDate;
    });

    // 2. Group by Representative (Using rep3 now)
    const repMap = new Map<string, CityViewRow>();

    filtered.forEach(item => {
      // Use rep3 for grouping
      const repKey = item.rep3;

      if (!repMap.has(repKey)) {
        repMap.set(repKey, {
          representativeName: repKey,
          active: 0,
          semiActive: 0,
          inactive: 0,
          total: 0
        });
      }
      const entry = repMap.get(repKey)!;

      if (item.status === ClientStatus.ACTIVE) entry.active++;
      else if (item.status === ClientStatus.SEMI_ACTIVE) entry.semiActive++;
      else if (item.status === ClientStatus.INACTIVE) entry.inactive++;

      entry.total++;
    });

    return Array.from(repMap.values()).sort((a, b) => a.representativeName.localeCompare(b.representativeName));
  }, [selectedSupervisor, startDate, endDate, data]);

  // Totals
  const totals = tableData.reduce((acc, curr) => ({
    active: acc.active + curr.active,
    semi: acc.semi + curr.semiActive,
    inactive: acc.inactive + curr.inactive,
    total: acc.total + curr.total
  }), { active: 0, semi: 0, inactive: 0, total: 0 });

  const activeRepsCount = tableData.length;

  const handleExport = () => {
    const csvData = tableData.map(row => ({
      'Supervisor': selectedSupervisor,
      'Representante': row.representativeName,
      'Ativo': row.active,
      'Semi-ativo': row.semiActive,
      'Inativo': row.inactive,
      'Total Geral': row.total
    }));
    onExport(csvData, `Status_Supervisor_${selectedSupervisor}_${startDate}_${endDate}`);
  };

  return (
    <div className="flex flex-col gap-6">
       {/* Header / Filters Container */}
       <div className="flex flex-col md:flex-row gap-0 border border-gray-200 shadow-lg rounded-2xl overflow-hidden">

        {/* Left Side: Info Panel */}
        <div className="flex-1 flex flex-col">
          {/* Supervisor Select - Searchable */}
          <div className="flex items-center bg-blue-900 text-white p-4 relative" ref={dropdownRef}>
            <span className="font-bold w-32 text-blue-200 shrink-0">Setor / Sup.</span>
            <div className="flex-1 relative group">
              <input 
                type="text"
                value={searchTerm}
                onChange={(e) => {
                  setSearchTerm(e.target.value);
                  setIsDropdownOpen(true);
                }}
                onClick={() => setIsDropdownOpen(true)}
                placeholder="Buscar supervisor..."
                className="w-full bg-blue-800/50 text-white border border-blue-700 rounded-lg text-sm p-2 pr-8 focus:outline-none focus:ring-2 focus:ring-blue-400 placeholder-blue-300 font-bold uppercase"
              />
               <div 
                className="absolute inset-y-0 right-0 flex items-center px-2 cursor-pointer text-blue-300 hover:text-white"
                onClick={() => setIsDropdownOpen(!isDropdownOpen)}
              >
                <i className={`fas fa-chevron-down text-xs transition-transform duration-200 ${isDropdownOpen ? 'transform rotate-180' : ''}`}></i>
              </div>

              {/* Dropdown List */}
              {isDropdownOpen && (
                <ul className="absolute left-0 top-full mt-1 w-full bg-white text-gray-800 rounded-lg shadow-xl max-h-60 overflow-y-auto z-50 animate-fade-in border border-gray-200">
                   {filteredOptions.length === 0 ? (
                    <li className="p-3 text-sm text-gray-400 text-center italic">Nenhum supervisor encontrado</li>
                  ) : (
                    filteredOptions.map((sup) => (
                      <li 
                        key={sup}
                        onClick={() => handleSelectSupervisor(sup)}
                        className={`px-4 py-2 text-sm cursor-pointer hover:bg-blue-50 hover:text-blue-700 transition-colors border-b border-gray-50 last:border-none uppercase ${sup === selectedSupervisor ? 'bg-blue-100 text-blue-900 font-bold' : ''}`}
                      >
                        {sup}
                      </li>
                    ))
                  )}
                </ul>
              )}
            </div>
          </div>

          <div className="flex-1 flex flex-col justify-center">
            <div className="flex items-center bg-yellow-400 text-blue-900 p-3 px-6 font-bold justify-between border-b border-yellow-300/50">
              <span className="uppercase text-xs opacity-80">Total Clientes (Filtro)</span>
              <span className="text-xl">{totals.total}</span>
            </div>
            <div className="flex items-center bg-blue-50 text-blue-900 p-3 px-6 font-bold justify-between">
              <span className="uppercase text-xs opacity-70">Representantes no Setor</span>
              <span className="text-lg">{activeRepsCount}</span>
            </div>
          </div>
        </div>

        {/* Right Side: Date & Actions */}
        <div className="w-full md:w-80 bg-gray-50 p-6 flex flex-col justify-center border-l border-gray-200">
          <div className="font-bold text-center mb-4 text-gray-500 uppercase text-xs tracking-wider">Período da Análise</div>

          <div className="space-y-3">
             <div className="flex justify-between items-center bg-white p-2 rounded-lg border border-gray-200 shadow-sm">
              <span className="font-bold text-gray-400 text-xs px-2">DE</span>
              <input 
                type="date" 
                value={startDate} 
                onChange={(e) => setStartDate(e.target.value)}
                className="text-right text-sm font-semibold text-gray-700 focus:outline-none bg-transparent"
              />
            </div>
            <div className="flex justify-between items-center bg-white p-2 rounded-lg border border-gray-200 shadow-sm">
              <span className="font-bold text-gray-400 text-xs px-2">ATÉ</span>
              <input 
                type="date" 
                value={endDate} 
                onChange={(e) => setEndDate(e.target.value)}
                className="text-right text-sm font-semibold text-gray-700 focus:outline-none bg-transparent"
              />
            </div>
          </div>

          <button 
            onClick={handleExport}
            className="mt-6 bg-green-600 hover:bg-green-700 text-white w-full py-3 rounded-xl text-sm font-bold flex justify-center items-center gap-2 shadow-md hover:shadow-lg transition-all"
          >
            <i className="fas fa-file-excel"></i> Exportar Dados
          </button>
        </div>
      </div>

      {/* Table */}
      <div className="overflow-hidden rounded-2xl shadow-lg border border-gray-200">
        <table className="w-full text-sm font-sans border-collapse">
          <thead>
            <tr className="text-white">
              <th className="bg-blue-900 text-left p-4 w-1/3">Representante (Rep 3)</th>
              <th className="bg-green-600 text-center p-4">Ativo</th>
              <th className="bg-orange-400 text-center p-4">Semi-Ativo</th>
              <th className="bg-red-600 text-center p-4">Inativo</th>
              <th className="bg-gray-900 text-center p-4">Total Geral</th>
            </tr>
          </thead>
          <tbody>
            {tableData.length === 0 ? (
               <tr><td colSpan={5} className="p-8 text-center text-gray-500 bg-gray-50">Nenhum dado para este período</td></tr>
            ) : (
              tableData.map((row, idx) => (
                <tr key={idx} className="bg-white border-b border-gray-100 hover:bg-blue-50 transition-colors text-gray-800">
                  <td className="p-3 px-4 font-medium border-r border-gray-100">{row.representativeName}</td>

                  {/* Active Cell */}
                  <td className="p-3 px-4 text-center border-r border-gray-100">
                    {row.active > 0 ? (
                       <button 
                         onClick={() => onDrillDown({ rep: row.representativeName, supervisor: selectedSupervisor, status: ClientStatus.ACTIVE })}
                         className="px-3 py-1 rounded-full bg-green-100 text-green-800 font-bold text-xs hover:bg-green-200 transition-colors"
                       >
                         {row.active}
                       </button>
                    ) : <span className="text-gray-300">-</span>}
                  </td>

                  {/* Semi-Active Cell */}
                  <td className="p-3 px-4 text-center border-r border-gray-100">
                    {row.semiActive > 0 ? (
                       <button 
                        onClick={() => onDrillDown({ rep: row.representativeName, supervisor: selectedSupervisor, status: ClientStatus.SEMI_ACTIVE })}
                        className="px-3 py-1 rounded-full bg-orange-100 text-orange-800 font-bold text-xs hover:bg-orange-200 transition-colors"
                       >
                         {row.semiActive}
                       </button>
                    ) : <span className="text-gray-300">-</span>}
                  </td>

                  {/* Inactive Cell */}
                  <td className="p-3 px-4 text-center border-r border-gray-100">
                    {row.inactive > 0 ? (
                       <button 
                        onClick={() => onDrillDown({ rep: row.representativeName, supervisor: selectedSupervisor, status: ClientStatus.INACTIVE })}
                        className="px-3 py-1 rounded-full bg-red-100 text-red-800 font-bold text-xs hover:bg-red-200 transition-colors"
                       >
                         {row.inactive}
                       </button>
                    ) : <span className="text-gray-300">-</span>}
                  </td>

                  {/* Total Cell */}
                  <td className="p-3 px-4 text-center font-bold text-gray-700">
                    {row.total > 0 ? (
                      <button 
                        onClick={() => onDrillDown({ rep: row.representativeName, supervisor: selectedSupervisor })}
                        className="px-3 py-1 rounded-full bg-gray-200 text-gray-900 font-bold text-xs hover:bg-gray-300 transition-colors"
                      >
                        {row.total}
                      </button>
                    ) : 0}
                  </td>
                </tr>
              ))
            )}
          </tbody>
          <tfoot>
            <tr className="text-white font-bold text-center">
              <td className="bg-blue-900 text-left p-4">Total Geral</td>
              <td 
                className="bg-green-600 p-4 cursor-pointer hover:bg-green-500 transition-colors"
                onClick={() => onDrillDown({ supervisor: selectedSupervisor, status: ClientStatus.ACTIVE })}
                title="Ver detalhes de Ativos"
              >
                {totals.active}
              </td>
              <td 
                className="bg-orange-500 p-4 cursor-pointer hover:bg-orange-400 transition-colors"
                onClick={() => onDrillDown({ supervisor: selectedSupervisor, status: ClientStatus.SEMI_ACTIVE })}
                title="Ver detalhes de Semi-ativos"
              >
                {totals.semi}
              </td>
              <td 
                className="bg-red-700 p-4 cursor-pointer hover:bg-red-600 transition-colors"
                onClick={() => onDrillDown({ supervisor: selectedSupervisor, status: ClientStatus.INACTIVE })}
                title="Ver detalhes de Inativos"
              >
                {totals.inactive}
              </td>
              <td 
                className="bg-gray-900 p-4 cursor-pointer hover:bg-gray-800 transition-colors"
                onClick={() => onDrillDown({ supervisor: selectedSupervisor })}
                title="Ver detalhes Geral"
              >
                {totals.total}
              </td>
            </tr>
          </tfoot>
        </table>
      </div>
    </div>
  );
};

export default SupervisorTab;

import React, { useState, useMemo, useEffect } from 'react';
import { ClientRecord } from '../types';

interface ClientListModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  clients: ClientRecord[];
}

const ClientListModal: React.FC<ClientListModalProps> = ({ isOpen, onClose, title, clients }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<{ key: keyof ClientRecord; direction: 'asc' | 'desc' }>({
    key: 'daysSincePurchase', // Default sort by Days
    direction: 'asc'          // Default ASC (smallest to largest)
  });

  // Reset filters and sort when modal opens
  useEffect(() => {
    if (isOpen) {
      setSearchTerm('');
      setSortConfig({ key: 'daysSincePurchase', direction: 'asc' });
    }
  }, [isOpen]);

  const handleSort = (key: keyof ClientRecord) => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const processedClients = useMemo(() => {
    let data = [...clients];

    // 1. Filter
    if (searchTerm.trim() !== '') {
      const lowerTerm = searchTerm.toLowerCase();
      data = data.filter(client => 
        client.socialName.toLowerCase().includes(lowerTerm) ||
        client.fantasyName.toLowerCase().includes(lowerTerm) ||
        client.id.toLowerCase().includes(lowerTerm) ||
        client.city.toLowerCase().includes(lowerTerm) ||
        client.neighborhood.toLowerCase().includes(lowerTerm) ||
        client.representativeName.toLowerCase().includes(lowerTerm) ||
        client.status.toLowerCase().includes(lowerTerm)
      );
    }

    // 2. Sort
    data.sort((a, b) => {
      const key = sortConfig.key;
      let valA: any = a[key];
      let valB: any = b[key];

      // Handle strings case-insensitive
      if (typeof valA === 'string') valA = valA.toLowerCase();
      if (typeof valB === 'string') valB = valB.toLowerCase();

      // Comparison
      if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
      if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });

    return data;
  }, [clients, searchTerm, sortConfig]);

  if (!isOpen) return null;

  // Helper to render sortable headers
  const renderHeader = (label: string, sortKey: keyof ClientRecord, align: 'left' | 'center' | 'right' = 'left') => (
    <th 
      className={`p-3 text-${align} font-bold text-gray-600 border-b cursor-pointer hover:bg-gray-100 transition-colors select-none whitespace-nowrap group`}
      onClick={() => handleSort(sortKey)}
    >
      <div className={`flex items-center gap-2 ${align === 'center' ? 'justify-center' : align === 'right' ? 'justify-end' : 'justify-start'}`}>
        {label}
        <div className="flex flex-col text-[10px] leading-none text-gray-400 group-hover:text-gray-500">
          <i className={`fas fa-caret-up ${sortConfig.key === sortKey && sortConfig.direction === 'asc' ? 'text-blue-600' : ''}`}></i>
          <i className={`fas fa-caret-down ${sortConfig.key === sortKey && sortConfig.direction === 'desc' ? 'text-blue-600' : ''}`}></i>
        </div>
      </div>
    </th>
  );

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-fade-in">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-7xl max-h-[90vh] flex flex-col overflow-hidden border border-gray-100">

        {/* Modal Header */}
        <div className="flex flex-col md:flex-row justify-between items-center bg-blue-900 text-white p-6 gap-4">
          <h3 className="text-2xl font-bold flex items-center gap-3">
            <div className="bg-blue-800 p-2 rounded-lg">
              <i className="fas fa-list"></i>
            </div>
            <span className="truncate max-w-md md:max-w-xl">{title}</span>
          </h3>

          <div className="flex items-center gap-3 w-full md:w-auto">
            {/* Search Input */}
            <div className="relative w-full md:w-64">
              <i className="fas fa-search absolute left-3 top-1/2 transform -translate-y-1/2 text-blue-300"></i>
              <input 
                type="text" 
                placeholder="Pesquisar na lista..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full bg-blue-800/50 border border-blue-700 text-white placeholder-blue-300 rounded-full py-2 pl-10 pr-4 focus:outline-none focus:ring-2 focus:ring-blue-400 focus:bg-blue-800 transition-all text-sm"
              />
            </div>

            <button 
              onClick={onClose} 
              className="w-10 h-10 flex items-center justify-center rounded-full bg-blue-800 text-white hover:bg-yellow-400 hover:text-blue-900 transition-colors shadow-lg"
            >
              <i className="fas fa-times"></i>
            </button>
          </div>
        </div>

        {/* Modal Content - Scrollable Table */}
        <div className="overflow-auto p-0 flex-1 bg-gray-50">
          <table className="min-w-full text-xs border-collapse">
            <thead className="bg-white sticky top-0 shadow-sm z-10">
              <tr>
                {renderHeader('Código', 'id')}
                {renderHeader('Razão Social', 'socialName')}
                {renderHeader('Fantasia', 'fantasyName')}
                {renderHeader('CNPJ', 'cnpj')}
                {renderHeader('Cidade/UF', 'city')}
                {renderHeader('Bairro', 'neighborhood')}
                {renderHeader('Ramo', 'activity')}
                {/* Renamed 'Dias' to 'Ult. Comp', Removed Date column */}
                {renderHeader('Ult. Comp', 'daysSincePurchase', 'center')}
                {renderHeader('Status', 'status', 'center')}
                {renderHeader('Representante', 'representativeName')}
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {processedClients.map((client, idx) => (
                <tr key={client.id} className={`hover:bg-blue-50/50 transition-colors ${idx % 2 === 0 ? 'bg-white' : 'bg-gray-50'}`}>
                  <td className="p-3 text-gray-500 font-mono">{client.id}</td>
                  <td className="p-3 font-bold text-gray-800">{client.socialName}</td>
                  <td className="p-3 text-gray-600">{client.fantasyName}</td>
                  <td className="p-3 whitespace-nowrap text-gray-500">{client.cnpj}</td>
                  <td className="p-3 text-gray-600">{client.city} - {client.state}</td>
                  <td className="p-3 text-gray-500">{client.neighborhood}</td>
                  <td className="p-3 text-gray-600">{client.activity}</td>
                  {/* Days since purchase cell */}
                  <td className="p-3 text-center">
                    <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${
                      client.daysSincePurchase > 60 ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'
                    }`}>
                      {client.daysSincePurchase}
                    </span>
                  </td>
                  <td className="p-3 text-center whitespace-nowrap">
                    <span className={`px-2 py-1 rounded-md text-xs font-bold border ${
                      client.status === 'Ativo' ? 'bg-green-50 text-green-700 border-green-200' :
                      client.status === 'Semi-Ativo' ? 'bg-orange-50 text-orange-700 border-orange-200' : 
                      'bg-red-50 text-red-700 border-red-200'
                    }`}>
                      {client.status}
                    </span>
                  </td>
                  <td className="p-3 text-gray-600">{client.representativeName}</td>
                </tr>
              ))}
              {processedClients.length === 0 && (
                <tr>
                  <td colSpan={10} className="text-center p-8 text-gray-400 italic">
                    {searchTerm ? `Nenhum resultado para "${searchTerm}"` : 'Nenhum registro encontrado.'}
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* Modal Footer */}
        <div className="bg-white p-4 border-t border-gray-100 flex justify-between items-center">
          <span className="text-sm font-bold text-gray-500 bg-gray-100 px-3 py-1 rounded-full">
            Total: {processedClients.length}
            {clients.length !== processedClients.length && <span className="text-xs font-normal ml-1"> (Filtrado de {clients.length})</span>}
          </span>
          <button 
            onClick={onClose}
            className="px-6 py-2.5 bg-gray-100 hover:bg-gray-200 text-gray-700 rounded-xl font-bold transition-all"
          >
            Fechar
          </button>
        </div>
      </div>
    </div>
  );
};

export default ClientListModal;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { ClientRecord, CityViewRow, ClientStatus } from '../types';

interface CityTabProps {
  data: ClientRecord[];
  onExport: (data: any[], filename: string) => void;
  onDrillDown: (filters: { rep?: string; city?: string; status?: ClientStatus | ClientStatus[] }) => void;
}

const CityTab: React.FC<CityTabProps> = ({ data, onExport, onDrillDown }) => {
  const [selectedCity, setSelectedCity] = useState<string>(''); // Stores "CITY - STATE"
  const [startDate, setStartDate] = useState('2022-01-01');
  const [endDate, setEndDate] = useState(new Date().toISOString().split('T')[0]);

  // Searchable Select States
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Extract unique cities with state "CITY - UF"
  const cities = useMemo(() => 
    Array.from(new Set(data.map(d => `${d.city} - ${d.state}`))).sort(),
  [data]);

  // Set default city if empty
  useEffect(() => {
    if ((!selectedCity || !cities.includes(selectedCity)) && cities.length > 0) {
      // Try to find BAURU or default to first
      const bauru = cities.find(c => c.toUpperCase().startsWith('BAURU'));
      const initial = bauru || cities[0];

      setSelectedCity(initial);
      setSearchTerm(initial);
    }
  }, [cities, selectedCity]);

  // Handle clicking outside to close dropdown
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsDropdownOpen(false);
        // Revert to selectedCity if invalid
        if (!cities.includes(searchTerm) && searchTerm !== '') {
           setSearchTerm(selectedCity);
        } else if (searchTerm === '') {
           setSearchTerm(selectedCity);
        }
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [dropdownRef, selectedCity, searchTerm, cities]);

  // Filtered Options
  const filteredOptions = useMemo(() => {
    if (!searchTerm) return cities;
    return cities.filter(c => 
      c.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [cities, searchTerm]);

  const handleSelectCity = (city: string) => {
    setSelectedCity(city);
    setSearchTerm(city);
    setIsDropdownOpen(false);
  };

  // Get current city population
  const currentCityPop = useMemo(() => {
    const record = data.find(d => `${d.city} - ${d.state}` === selectedCity);
    return record ? record.population : 0;
  }, [selectedCity, data]);

  // Filter and Aggregate Data
  const tableData = useMemo(() => {
    if (!selectedCity) return [];

    // 1. Filter by City+State Key and Date
    const filtered = data.filter(item => {
      const itemKey = `${item.city} - ${item.state}`;
      const matchCity = itemKey === selectedCity;
      const matchDate = item.lastPurchaseDate >= startDate && item.lastPurchaseDate <= endDate;
      return matchCity && matchDate;
    });

    // 2. Group by Representative (Using rep3 now)
    const repMap = new Map<string, CityViewRow>();

    filtered.forEach(item => {
      // Use rep3 for grouping
      const repKey = item.rep3;

      if (!repMap.has(repKey)) {
        repMap.set(repKey, {
          representativeName: repKey,
          active: 0,
          semiActive: 0,
          inactive: 0,
          total: 0
        });
      }
      const entry = repMap.get(repKey)!;

      if (item.status === ClientStatus.ACTIVE) entry.active++;
      else if (item.status === ClientStatus.SEMI_ACTIVE) entry.semiActive++;
      else if (item.status === ClientStatus.INACTIVE) entry.inactive++;

      entry.total++;
    });

    return Array.from(repMap.values()).sort((a, b) => a.representativeName.localeCompare(b.representativeName));
  }, [selectedCity, startDate, endDate, data]);

  // Totals
  const totals = tableData.reduce((acc, curr) => ({
    active: acc.active + curr.active,
    semi: acc.semi + curr.semiActive,
    inactive: acc.inactive + curr.inactive,
    total: acc.total + curr.total
  }), { active: 0, semi: 0, inactive: 0, total: 0 });

