import React, { useState, useRef, useEffect } from 'react';
import RepresentativeTab from './components/RepresentativeTab';
import CityTab from './components/CityTab';
import SupervisorTab from './components/SupervisorTab';
import ClientListModal from './components/ClientListModal';
import { MOCK_DATA } from './services/mockData';
import { ClientRecord, ClientStatus } from './types';

type Tab = 'representative' | 'city' | 'supervisor';

const STORAGE_KEY = 'MILLENIUM_DASHBOARD_DATA_V2';
const TAB_STORAGE_KEY = 'MILLENIUM_PREF_ACTIVE_TAB';

const App: React.FC = () => {
  // Load active tab from storage or default to representative
  const [activeTab, setActiveTab] = useState<Tab>(() => {
    return (localStorage.getItem(TAB_STORAGE_KEY) as Tab) || 'representative';
  });

  // Save active tab whenever it changes
  useEffect(() => {
    localStorage.setItem(TAB_STORAGE_KEY, activeTab);
  }, [activeTab]);

  // Initialize state from LocalStorage if available, else Mock Data
  const [clientData, setClientData] = useState<ClientRecord[]>(() => {
    try {
      const savedData = localStorage.getItem(STORAGE_KEY);
      if (savedData) {
        console.log("Dados carregados do cache local.");
        return JSON.parse(savedData);
      }
      return MOCK_DATA;
    } catch (error) {
      console.error("Erro ao carregar do cache:", error);
      return MOCK_DATA;
    }
  });

  // Track if we are using local data or mock data for internal logic
  const [isLocalData, setIsLocalData] = useState<boolean>(() => {
    return !!localStorage.getItem(STORAGE_KEY);
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Modal State
  const [modalOpen, setModalOpen] = useState(false);
  const [modalTitle, setModalTitle] = useState('');
  const [modalClients, setModalClients] = useState<ClientRecord[]>([]);

  // Export Logic
  const exportToCSV = (data: any[], filename: string) => {
    if (!data || !data.length) {
      alert("Não há dados para exportar.");
      return;
    }
    const headers = Object.keys(data[0]);
    const csvContent = [
      headers.join(';'),
      ...data.map(row => headers.map(fieldName => {
         let val = row[fieldName];
         if (val === null || val === undefined) val = '';
         val = String(val);
         if (val.includes('"') || val.includes(';')) {
           val = `"${val.replace(/"/g, '""')}"`;
         }
         return val;
      }).join(';'))
    ].join('\r\n');

    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    if (link.download !== undefined) { 
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        link.setAttribute("download", `${filename}.csv`);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    }
  };

  // Download Template based on the image structure + Supervisor
  const handleDownloadTemplate = () => {
    const headers = [
      "Código", "Razão Social / Nome", "Nome Fantasia", "CNPJ", "I. E.", 
      "Cidade", "UF", "Endereço (Logradouro)", "Número", "Bairro", "CEP", 
      "Ramo de atividade", "Grupo", "Ult. Compra", "Dias", "Cadastro", 
      "Representante Padrão", "Situação de bloqueio", "Situação do Cliente", 
      "Motivo de bloqueio", "pesquisa de ordem.Representante", "Representante Padrão - Copiar", 
      "Cidades", "Habitantes", "Rep", "rep2", "rep 3", "Supervisor"
    ];

    // Example row matching headers
    const exampleRow = [
      "4523", "WILMA DA SILVA GARCIA - ME", "WILMA DA SILVA GARCIA", "04.744.767/0001-86", 
      "156.072.736.119", "AGUDOS", "SP", "R.TREZE DE MAIO", "482", "CENTRO", 
      "17120-000", "SUPERMERCADO", "", "01/11/2025", "35", "02/01/1900", 
      "DINA GOUP.SAIU", "Normal", "Semi-ativo", "", "DINA", "DINA", 
      "AGUDOS - SP", "37401", "DINA", "DINA", "DINA", "SUPERVISAO INTERIOR"
    ];

    const csvContent = [
      headers.join(';'),
      exampleRow.join(';')
    ].join('\r\n');

    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", "modelo_importacao_curva_abc.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Import Logic - Updated to map columns
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      const text = e.target?.result as string;
      if (!text) return;

      try {
        const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
        const dataLines = lines.slice(1);

        const newRecords: ClientRecord[] = dataLines.map((line, index) => {
          const cols = line.split(';');

          if (cols.length < 5) return null;

          const statusRaw = cols[18]?.replace(/"/g, '').trim();
          let status = ClientStatus.ACTIVE;
          if (statusRaw === 'Semi-ativo') status = ClientStatus.SEMI_ACTIVE;
          if (statusRaw === 'Inativo') status = ClientStatus.INACTIVE;

          // Parse date DD/MM/YYYY to YYYY-MM-DD
          const parseDate = (d: string) => {
            const parts = d.replace(/"/g, '').trim().split('/');
            if (parts.length === 3) return `${parts[2]}-${parts[1]}-${parts[0]}`;
            return new Date().toISOString().split('T')[0];
          };

          const standardRep = cols[24]?.replace(/"/g, '').trim() || cols[20]?.replace(/"/g, '').trim() || 'Indefinido';
          // Ensure rep3 falls back to standard rep if empty
          const rep3 = cols[26]?.replace(/"/g, '').trim() || standardRep;

          return {
            id: cols[0]?.replace(/"/g, '').trim() || `IMP-${index}`,
            socialName: cols[1]?.replace(/"/g, '').trim() || '',
            fantasyName: cols[2]?.replace(/"/g, '').trim() || '',
            cnpj: cols[3]?.replace(/"/g, '').trim() || '',
            ie: cols[4]?.replace(/"/g, '').trim() || '',
            city: cols[5]?.replace(/"/g, '').trim() || '',
            state: cols[6]?.replace(/"/g, '').trim() || '',
            address: `${cols[7]?.replace(/"/g, '').trim() || ''}, ${cols[8]?.replace(/"/g, '').trim() || ''}`,
            neighborhood: cols[9]?.replace(/"/g, '').trim() || '',
            cep: cols[10]?.replace(/"/g, '').trim() || '',
            activity: cols[11]?.replace(/"/g, '').trim() || '',
            group: cols[12]?.replace(/"/g, '').trim() || '',
            lastPurchaseDate: parseDate(cols[13] || ''),
            daysSincePurchase: parseInt(cols[14]?.replace(/\D/g, '') || '0', 10),
            registerDate: parseDate(cols[15] || ''),
            representativeName: standardRep,
            population: parseInt(cols[23]?.replace(/\D/g, '') || '0', 10),
            status: status,
            rep3: rep3, // Import Rep 3 specifically
            supervisor: cols[27]?.replace(/"/g, '').trim() || 'GERAL'
          };
        }).filter(r => r !== null) as ClientRecord[];

        if (newRecords.length > 0) {
          setClientData(newRecords);
          setIsLocalData(true);
          // SAVE TO LOCAL STORAGE
          try {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(newRecords));
            alert(`${newRecords.length} registros importados! Os dados foram salvos no seu navegador e aparecerão automaticamente na próxima vez.`);
          } catch (e: any) {
            console.error(e);
            if (e.name === 'QuotaExceededError') {
                alert(`${newRecords.length} registros importados, mas NÃO FOI POSSÍVEL SALVAR NO CACHE. O arquivo é muito grande para o navegador (Limite aprox 5MB). Os dados funcionarão agora, mas serão perdidos ao fechar a página.`);
            } else {
                alert(`Erro ao salvar no cache: ${e.message}`);
            }
          }
        } else {
          alert('Nenhum registro válido encontrado ou formato incorreto.');
        }

      } catch (err) {
        console.error(err);
        alert('Erro ao processar arquivo. Verifique se o formato corresponde ao modelo.');
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  // Function to Clear Data (Reset to Mock)
  const handleResetData = () => {
    if (confirm("Tem certeza que deseja resetar para os dados de exemplo e limpar o cache?")) {
      setClientData(MOCK_DATA);
      localStorage.removeItem(STORAGE_KEY);
      localStorage.removeItem(TAB_STORAGE_KEY);
      // Also clear preference keys from tabs
      localStorage.removeItem('MILLENIUM_PREF_REP_NAME');
      localStorage.removeItem('MILLENIUM_PREF_CITY_NAME');
      localStorage.removeItem('MILLENIUM_PREF_SUP_NAME');
      localStorage.removeItem('MILLENIUM_PREF_DATE_START');
      localStorage.removeItem('MILLENIUM_PREF_DATE_END');

      setIsLocalData(false);
      window.location.reload(); // Reload to ensure clean slate
    }
  };

  // Drill-down handler
  const handleDrillDown = (filters: { rep?: string; city?: string; status?: ClientStatus | ClientStatus[]; supervisor?: string }) => {
    let filtered = clientData;

    // Filter by Representative - Strictly uses 'rep3' as requested
    if (filters.rep) {
      filtered = filtered.filter(c => c.rep3 === filters.rep);
    }

    // Filter by City
    if (filters.city) {
      filtered = filtered.filter(c => c.city === filters.city);
    }

    // Filter by Supervisor
    if (filters.supervisor) {
        filtered = filtered.filter(c => c.supervisor === filters.supervisor);
    }

    // Filter by Status (Only if provided)
    if (filters.status) {
      if (Array.isArray(filters.status)) {
        filtered = filtered.filter(c => (filters.status as ClientStatus[]).includes(c.status));
      } else {
        filtered = filtered.filter(c => c.status === filters.status);
      }
    }

    // Create a descriptive title
    let titleParts = [];
    if (filters.rep) titleParts.push(`Rep: ${filters.rep}`);
    if (filters.supervisor) titleParts.push(`Sup: ${filters.supervisor}`);
    if (filters.city) titleParts.push(`Cidade: ${filters.city}`);

    if (filters.status) {
       const statusStr = Array.isArray(filters.status) ? filters.status.join(' + ') : filters.status;
       titleParts.push(`Status: ${statusStr}`);
    } else {
       titleParts.push(`Status: Geral (Todos)`);
    }

    setModalTitle(`Detalhes - ${titleParts.join(' | ')}`);
    setModalClients(filtered);
    setModalOpen(true);
  };

  return (
    <div className="min-h-screen bg-gray-100 p-4 md:p-6 font-sans text-gray-800">
      <div className="max-w-6xl mx-auto bg-white shadow-2xl rounded-3xl overflow-hidden border border-gray-100">

