import { ClientRecord } from '../types';

const DB_NAME = 'MilleniumDashboardDB';
const DB_VERSION = 1;
const STORE_NAME = 'clients';

export const dbService = {
  openDB: (): Promise<IDBDatabase> => {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, DB_VERSION);

      request.onupgradeneeded = (event) => {
        const db = (event.target as IDBOpenDBRequest).result;
        if (!db.objectStoreNames.contains(STORE_NAME)) {
          // We create a store. We don't need a keyPath if we store the whole array as one object,
          // but for scalability let's store individual records with 'id' as key.
          db.createObjectStore(STORE_NAME, { keyPath: 'id' });
        }
      };

      request.onsuccess = (event) => {
        resolve((event.target as IDBOpenDBRequest).result);
      };

      request.onerror = (event) => {
        reject((event.target as IDBOpenDBRequest).error);
      };
    });
  },

  saveClients: async (clients: ClientRecord[]): Promise<void> => {
    const db = await dbService.openDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction([STORE_NAME], 'readwrite');
      const store = transaction.objectStore(STORE_NAME);

      // Clear old data first to avoid duplicates or ghosts
      store.clear();

      // Bulk add
      clients.forEach(client => {
        store.put(client);
      });

      transaction.oncomplete = () => {
        resolve();
      };

      transaction.onerror = () => {
        reject(transaction.error);
      };
    });
  },

  getAllClients: async (): Promise<ClientRecord[]> => {
    const db = await dbService.openDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction([STORE_NAME], 'readonly');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.getAll();

      request.onsuccess = () => {
        resolve(request.result as ClientRecord[]);
      };

      request.onerror = () => {
        reject(request.error);
      };
    });
  },

  clearDB: async (): Promise<void> => {
    const db = await dbService.openDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction([STORE_NAME], 'readwrite');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.clear();

      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  }
};

