    const saved = localStorage.getItem(GITHUB_CONFIG_KEY);
    return saved ? JSON.parse(saved) : {
      token: '',
      owner: '', // Seu usuário GitHub
      repo: '',  // Nome do repositório
      path: 'services/mockData.ts',
      branch: 'main'
    };
  });

