                </button>

                {/* Fallback Manual Save */}
                <button onClick={handleSaveToSourceManual} className="bg-purple-600/80 hover:bg-purple-500 text-white px-2 py-2 rounded-lg text-xs font-bold shadow-sm" title="Baixar arquivo manualmente">
                  <i className="fas fa-file-code"></i>
                </button>

                <button onClick={handleResetData} className="bg-red-500/80 hover:bg-red-500 text-white px-3 py-2 rounded-lg text-xs font-bold shadow-sm" title="Resetar">
                  <i className="fas fa-trash"></i>
                </button>
              </div>
            </div>
          </div>

          <div className="flex flex-wrap border-b border-gray-200 bg-gray-50/50 p-2 gap-2">
            {[
              { id: 'representative', icon: 'fa-user-tie', label: 'Representante' },
              { id: 'city', icon: 'fa-city', label: 'Cidade' },
              { id: 'supervisor', icon: 'fa-user-shield', label: 'Supervisor' }
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as Tab)}
                className={`flex-1 py-3 px-4 rounded-xl text-center font-bold text-sm transition-all duration-200 ${
                  activeTab === tab.id
                    ? 'bg-white text-blue-900 shadow-md ring-1 ring-black/5'
                    : 'text-gray-500 hover:text-blue-700 hover:bg-gray-100'
                }`}
              >
                <i className={`fas ${tab.icon} mr-2`}></i> {tab.label}
              </button>
            ))}
          </div>

          <div className="p-6 md:p-8 bg-white min-h-[500px]">
            {activeTab === 'representative' ? (
              <RepresentativeTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} />
            ) : activeTab === 'city' ? (
              <CityTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} />
            ) : (
              <SupervisorTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} />
            )}
          </div>

          <div className="bg-gray-50 p-4 text-center text-xs text-gray-400 border-t border-gray-100">
            &copy; {new Date().getFullYear()} Millenium Utilidades.
          </div>
        </div>
        <ClientListModal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={modalTitle} clients={modalClients} />
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import RepresentativeTab from './components/RepresentativeTab';
import CityTab from './components/CityTab';
import SupervisorTab from './components/SupervisorTab';
import ClientListModal from './components/ClientListModal';
import { MOCK_DATA } from './services/mockData';
import { dbService } from './services/database'; 
import { ClientRecord, ClientStatus } from './types';

type Tab = 'representative' | 'city' | 'supervisor';
type DataSource = 'MOCK' | 'LOCAL_DB';

const TAB_STORAGE_KEY = 'MILLENIUM_PREF_ACTIVE_TAB';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>(() => {
    return (localStorage.getItem(TAB_STORAGE_KEY) as Tab) || 'representative';
  });

  const [isLoading, setIsLoading] = useState(true);
  const [loadingMsg, setLoadingMsg] = useState('Processando...');
  const [clientData, setClientData] = useState<ClientRecord[]>([]);
  const [dataSource, setDataSource] = useState<DataSource>('MOCK');

  // Load Data on Startup
  useEffect(() => {
    const loadData = async () => {
      setIsLoading(true);
      setLoadingMsg('Carregando dados...');
      try {
        const dbData = await dbService.getAllClients();
        if (dbData && dbData.length > 0) {
          console.log(`Carregado ${dbData.length} registros do DB.`);
          setClientData(dbData);
          setDataSource('LOCAL_DB');
        } else {
          console.log("DB vazio, usando Mock.");
          setClientData(MOCK_DATA);
          setDataSource('MOCK');
        }
      } catch (error) {
        console.error("Erro DB:", error);
        setClientData(MOCK_DATA);
        setDataSource('MOCK');
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, []);

  useEffect(() => {
    localStorage.setItem(TAB_STORAGE_KEY, activeTab);
  }, [activeTab]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [modalOpen, setModalOpen] = useState(false);
  const [modalTitle, setModalTitle] = useState('');
  const [modalClients, setModalClients] = useState<ClientRecord[]>([]);

  // CSV Export
  const exportToCSV = (data: any[], filename: string) => {
    if (!data || !data.length) {
      alert("Sem dados para exportar.");
      return;
    }
    const headers = Object.keys(data[0]);
    const csvContent = [
      headers.join(';'),
      ...data.map(row => headers.map(fieldName => {
         let val = row[fieldName];
         if (val === null || val === undefined) val = '';
         val = String(val);
         if (val.includes('"') || val.includes(';')) val = `"${val.replace(/"/g, '""')}"`;
         return val;
      }).join(';'))
    ].join('\r\n');

    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `${filename}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Template Download
  const handleDownloadTemplate = () => {
    const headers = [
      "Código", "Razão Social / Nome", "Nome Fantasia", "CNPJ", "I. E.", 
      "Cidade", "UF", "Endereço (Logradouro)", "Número", "Bairro", "CEP", 
      "Ramo de atividade", "Grupo", "Ult. Compra", "Dias", "Cadastro", 
      "Representante Padrão", "Situação de bloqueio", "Situação do Cliente", 
      "Motivo de bloqueio", "pesquisa de ordem.Representante", "Representante Padrão - Copiar", 
      "Cidades", "Habitantes", "Rep", "rep2", "rep 3", "Supervisor"
    ];
    const exampleRow = [
      "4523", "CLIENTE EXEMPLO LTDA", "MERCADO EXEMPLO", "00.000.000/0001-00", 
      "123.456.789", "BAURU", "SP", "RUA EXEMPLO", "100", "CENTRO", 
      "17000-000", "SUPERMERCADO", "", "01/01/2024", "10", "01/01/2020", 
      "REP EXEMPLO", "Normal", "Ativo", "", "REP EXEMPLO", "REP EXEMPLO", 
      "BAURU - SP", "379297", "REP EXEMPLO", "REP EXEMPLO", "REP EXEMPLO", "SUPERVISAO GERAL"
    ];
    const csvContent = [headers.join(';'), exampleRow.join(';')].join('\r\n');
    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", "modelo_importacao.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Import CSV
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    setLoadingMsg('Importando CSV...');

    const reader = new FileReader();
    reader.onload = async (e) => {
      const text = e.target?.result as string;
      if (!text) { setIsLoading(false); return; }

      try {
        const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
        // Check delimiter
        const firstLine = lines[0];
        const delimiter = firstLine.includes(';') ? ';' : ',';

        const dataLines = lines.slice(1);

        const newRecords: ClientRecord[] = dataLines.map((line, index) => {
          const cols = line.split(delimiter);
          if (cols.length < 5) return null;

          const clean = (val: string) => val ? val.replace(/"/g, '').trim() : '';

          const statusRaw = clean(cols[18]);
          let status = ClientStatus.ACTIVE;
          if (statusRaw === 'Semi-ativo') status = ClientStatus.SEMI_ACTIVE;
          if (statusRaw === 'Inativo') status = ClientStatus.INACTIVE;

          const parseDate = (d: string) => {
            const c = clean(d);
            const parts = c.split('/');
            if (parts.length === 3) return `${parts[2]}-${parts[1]}-${parts[0]}`;
            return c.includes('-') ? c : new Date().toISOString().split('T')[0];
          };

          const standardRep = clean(cols[24]) || clean(cols[20]) || 'Indefinido';
          const rep3 = clean(cols[26]) || standardRep;
          const supervisor = clean(cols[27]) || 'GERAL';

          return {
            id: clean(cols[0]) || `IMP-${index}`,
            socialName: clean(cols[1]),
            fantasyName: clean(cols[2]),
            cnpj: clean(cols[3]),
            ie: clean(cols[4]),
            city: clean(cols[5]),
            state: clean(cols[6]),
            address: `${clean(cols[7])}, ${clean(cols[8])}`,
            neighborhood: clean(cols[9]),
            cep: clean(cols[10]),
            activity: clean(cols[11]),
            group: clean(cols[12]),
            lastPurchaseDate: parseDate(cols[13]),
            daysSincePurchase: parseInt(clean(cols[14]).replace(/\D/g, '') || '0', 10),
            registerDate: parseDate(cols[15]),
            representativeName: standardRep,
            population: parseInt(clean(cols[23]).replace(/\D/g, '') || '0', 10),
            status: status,
            rep3: rep3, 
            supervisor: supervisor
          };
        }).filter(r => r !== null) as ClientRecord[];

        if (newRecords.length > 0) {
          // Save to DB
          await dbService.saveClients(newRecords);
          setClientData(newRecords);
          setDataSource('LOCAL_DB');
          alert(`${newRecords.length} registros importados e salvos no navegador!`);
        } else {
          alert('Arquivo vazio ou formato incorreto.');
        }
      } catch (err) {
        console.error(err);
        alert('Erro ao processar arquivo. Verifique se é um CSV válido.');
      } finally {
        setIsLoading(false);
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  const handleResetData = async () => {
    if (confirm("Deseja apagar os dados importados e voltar ao padrão do sistema?")) {
      setIsLoading(true);
      await dbService.clearDB();
      localStorage.clear(); 
      window.location.reload();
    }
  };

  const handleDrillDown = (filters: any) => {
    let filtered = clientData;
    if (filters.rep) filtered = filtered.filter(c => c.rep3 === filters.rep);
    if (filters.city) filtered = filtered.filter(c => c.city === filters.city);
    if (filters.supervisor) filtered = filtered.filter(c => c.supervisor === filters.supervisor);
    if (filters.status) {
      if (Array.isArray(filters.status)) filtered = filtered.filter(c => (filters.status as any).includes(c.status));
      else filtered = filtered.filter(c => c.status === filters.status);
    }

    let titleParts = [];
    if (filters.rep) titleParts.push(`Rep: ${filters.rep}`);
    if (filters.supervisor) titleParts.push(`Sup: ${filters.supervisor}`);
    if (filters.city) titleParts.push(`Cidade: ${filters.city}`);
    setModalTitle(`Detalhes - ${titleParts.join(' | ')}`);
    setModalClients(filtered);
    setModalOpen(true);
  };

  return (
    <div className="min-h-screen bg-gray-100 font-sans text-gray-800">

      {/* Top Status Bar */}
      <div className={`w-full py-1 text-center text-xs font-bold uppercase tracking-wider text-white flex justify-center items-center gap-4 ${dataSource === 'LOCAL_DB' ? 'bg-green-600' : 'bg-gray-500'}`}>
        <span>
          {dataSource === 'LOCAL_DB' 
            ? <><i className="fas fa-database mr-2"></i> Usando Dados Locais</> 
            : <><i className="fas fa-file-code mr-2"></i> Usando Dados Padrão</>}
        </span>
      </div>

      {isLoading && (
        <div className="fixed inset-0 bg-black/50 z-[100] flex items-center justify-center backdrop-blur-sm">
           <div className="bg-white p-6 rounded-2xl shadow-2xl flex flex-col items-center">
             <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-900 mb-4"></div>
             <p className="text-blue-900 font-bold">{loadingMsg}</p>
           </div>
        </div>
      )}

      <div className="p-4 md:p-6">
        <div className="max-w-6xl mx-auto bg-white shadow-2xl rounded-3xl overflow-hidden border border-gray-100">

          <div className="bg-gradient-to-r from-blue-900 to-blue-800 text-white p-6 rounded-t-3xl">
            <div className="flex flex-col md:flex-row justify-between items-center gap-6">
              <div>
                <h1 className="text-3xl font-bold tracking-tight flex items-center gap-3">
                  <i className="fas fa-chart-pie"></i>
                  Curva ABC
                </h1>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-blue-200 text-sm font-medium tracking-wide">Millenium Utilidades</span>
                </div>
              </div>

              <div className="flex flex-wrap justify-center gap-2 items-center">
                <button onClick={handleDownloadTemplate} className="bg-white/10 hover:bg-white/20 text-white px-3 py-2 rounded-lg text-xs font-semibold flex items-center gap-2 border border-white/20">
                  <i className="fas fa-download"></i> Modelo
                </button>

                <div className="relative">
                  <input type="file" accept=".csv" ref={fileInputRef} onChange={handleFileUpload} className="hidden" />
                  <button onClick={() => fileInputRef.current?.click()} className="bg-yellow-400 hover:bg-yellow-300 text-blue-900 px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 shadow-lg">
                    <i className="fas fa-file-import"></i> Importar
                  </button>
                </div>

                <div className="h-8 w-px bg-white/20 mx-1"></div>

                <button onClick={handleResetData} className="bg-red-500/80 hover:bg-red-500 text-white px-3 py-2 rounded-lg text-xs font-bold shadow-sm" title="Resetar">
                  <i className="fas fa-trash"></i>
                </button>
              </div>
            </div>
          </div>

          <div className="flex flex-wrap border-b border-gray-200 bg-gray-50/50 p-2 gap-2">
            {[
              { id: 'representative', icon: 'fa-user-tie', label: 'Representante' },
              { id: 'city', icon: 'fa-city', label: 'Cidade' },
              { id: 'supervisor', icon: 'fa-user-shield', label: 'Supervisor' }
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as Tab)}
                className={`flex-1 py-3 px-4 rounded-xl text-center font-bold text-sm transition-all duration-200 ${
                  activeTab === tab.id
                    ? 'bg-white text-blue-900 shadow-md ring-1 ring-black/5'
                    : 'text-gray-500 hover:text-blue-700 hover:bg-gray-100'
                }`}
              >
                <i className={`fas ${tab.icon} mr-2`}></i> {tab.label}
              </button>
            ))}
          </div>

          <div className="p-6 md:p-8 bg-white min-h-[500px]">
            {activeTab === 'representative' ? (
              <RepresentativeTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} />
            ) : activeTab === 'city' ? (
              <CityTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} />
            ) : (
              <SupervisorTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} />
            )}
          </div>

          <div className="bg-gray-50 p-4 text-center text-xs text-gray-400 border-t border-gray-100">
            &copy; {new Date().getFullYear()} Millenium Utilidades.
          </div>
        </div>
        <ClientListModal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={modalTitle} clients={modalClients} />
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { ClientRecord, CityViewRow, ClientStatus } from '../types';
import { useVirtualizer } from '../hooks/useVirtualizer';

interface SupervisorTabProps {
  data: ClientRecord[];
  onExport: (data: any[], filename: string) => void;
  onDrillDown: (filters: { rep?: string; city?: string; status?: ClientStatus | ClientStatus[]; supervisor?: string }) => void;
}

const ITEM_HEIGHT = 57; // Estimated row height

// Persistence Keys
const KEY_SUP_NAME = 'MILLENIUM_PREF_SUP_NAME';
const KEY_DATE_START = 'MILLENIUM_PREF_DATE_START';
const KEY_DATE_END = 'MILLENIUM_PREF_DATE_END';

const SupervisorTab: React.FC<SupervisorTabProps> = ({ data, onExport, onDrillDown }) => {
  // Initialize from LocalStorage
  const [selectedSupervisor, setSelectedSupervisor] = useState<string>(() => localStorage.getItem(KEY_SUP_NAME) || '');
  const [startDate, setStartDate] = useState(() => localStorage.getItem(KEY_DATE_START) || '2022-01-01');
  const [endDate, setEndDate] = useState(() => localStorage.getItem(KEY_DATE_END) || new Date().toISOString().split('T')[0]);

  // Persist Changes
  useEffect(() => { if (selectedSupervisor) localStorage.setItem(KEY_SUP_NAME, selectedSupervisor); }, [selectedSupervisor]);
  useEffect(() => { localStorage.setItem(KEY_DATE_START, startDate); }, [startDate]);
  useEffect(() => { localStorage.setItem(KEY_DATE_END, endDate); }, [endDate]);

  // Searchable Select States
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState(selectedSupervisor);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Sync SearchTerm
  useEffect(() => { if (selectedSupervisor) setSearchTerm(selectedSupervisor); }, [selectedSupervisor]);

  // Extract unique Supervisors
  const supervisors = useMemo(() => 
    Array.from(new Set(data.map(d => d.supervisor))).sort(),
  [data]);

  // Set default supervisor if empty
  useEffect(() => {
    if (supervisors.length > 0) {
      if (!selectedSupervisor || !supervisors.includes(selectedSupervisor)) {
        const initial = supervisors[0];
        setSelectedSupervisor(initial);
        setSearchTerm(initial);
      }
    }
  }, [supervisors, selectedSupervisor]);

  // Handle clicking outside to close dropdown
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsDropdownOpen(false);
        // Revert to selectedSupervisor if invalid
        if (!supervisors.includes(searchTerm) && searchTerm !== '') {
           setSearchTerm(selectedSupervisor);
        } else if (searchTerm === '') {
           setSearchTerm(selectedSupervisor);
        }
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [dropdownRef, selectedSupervisor, searchTerm, supervisors]);

  // Filtered Options
  const filteredOptions = useMemo(() => {
    if (!searchTerm) return supervisors;
    return supervisors.filter(s => 
      s.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [supervisors, searchTerm]);

  const handleSelectSupervisor = (sup: string) => {
    setSelectedSupervisor(sup);
    setSearchTerm(sup);
    setIsDropdownOpen(false);
  };

  // Filter and Aggregate Data
  const tableData = useMemo(() => {
    if (!selectedSupervisor) return [];

    // 1. Filter by Supervisor and Date
    const filtered = data.filter(item => {
      const matchSup = item.supervisor === selectedSupervisor;
      const matchDate = item.lastPurchaseDate >= startDate && item.lastPurchaseDate <= endDate;
      return matchSup && matchDate;
    });

    // 2. Group by Representative (Using rep3 now)
    const repMap = new Map<string, CityViewRow>();

    filtered.forEach(item => {
      // Use rep3 for grouping
      const repKey = item.rep3;

      if (!repMap.has(repKey)) {
        repMap.set(repKey, {
          representativeName: repKey,
          active: 0,
          semiActive: 0,
          inactive: 0,
          total: 0
        });
      }
      const entry = repMap.get(repKey)!;

      if (item.status === ClientStatus.ACTIVE) entry.active++;
      else if (item.status === ClientStatus.SEMI_ACTIVE) entry.semiActive++;
      else if (item.status === ClientStatus.INACTIVE) entry.inactive++;

      entry.total++;
    });

    return Array.from(repMap.values()).sort((a, b) => a.representativeName.localeCompare(b.representativeName));
  }, [selectedSupervisor, startDate, endDate, data]);

  // Totals
  const totals = tableData.reduce((acc, curr) => ({
    active: acc.active + curr.active,
    semi: acc.semi + curr.semiActive,
    inactive: acc.inactive + curr.inactive,
    total: acc.total + curr.total
  }), { active: 0, semi: 0, inactive: 0, total: 0 });

  const activeRepsCount = tableData.length;

  const handleExport = () => {
    const csvData = tableData.map(row => ({
      'Supervisor': selectedSupervisor,
      'Representante': row.representativeName,
      'Ativo': row.active,
      'Semi-ativo': row.semiActive,
      'Inativo': row.inactive,
      'Total Geral': row.total
    }));
    onExport(csvData, `Status_Supervisor_${selectedSupervisor}_${startDate}_${endDate}`);
  };

  // Virtualization
  const { virtualItems, paddingTop, paddingBottom } = useVirtualizer({
    count: tableData.length,
    itemHeight: ITEM_HEIGHT,
    containerRef: containerRef,
    overscan: 5
  });

  return (
    <div className="flex flex-col gap-6">
       {/* Header / Filters Container */}
       {/* Removed overflow-hidden and added specific rounding to children to allow dropdown overflow */}
       <div className="flex flex-col md:flex-row gap-0 border border-gray-200 shadow-lg rounded-2xl relative z-20">

        {/* Left Side: Info Panel */}
        <div className="flex-1 flex flex-col">
          {/* Supervisor Select - Searchable */}
          {/* Added rounding to top left/right based on breakpoint */}
          <div className="flex items-center bg-blue-900 text-white p-4 relative rounded-t-2xl md:rounded-tr-none md:rounded-tl-2xl" ref={dropdownRef}>
            <span className="font-bold w-32 text-blue-200 shrink-0">Setor / Sup.</span>
            <div className="flex-1 relative group">
              <input 
                type="text"
                value={searchTerm}
                onChange={(e) => {
                  setSearchTerm(e.target.value);
                  setIsDropdownOpen(true);
                }}
                onClick={() => setIsDropdownOpen(true)}
                placeholder="Buscar supervisor..."
                className="w-full bg-blue-800/50 text-white border border-blue-700 rounded-lg text-sm p-2 pr-8 focus:outline-none focus:ring-2 focus:ring-blue-400 placeholder-blue-300 font-bold uppercase"
              />
               <div 
                className="absolute inset-y-0 right-0 flex items-center px-2 cursor-pointer text-blue-300 hover:text-white"
                onClick={() => setIsDropdownOpen(!isDropdownOpen)}
              >
                <i className={`fas fa-chevron-down text-xs transition-transform duration-200 ${isDropdownOpen ? 'transform rotate-180' : ''}`}></i>
              </div>

              {/* Dropdown List */}
              {isDropdownOpen && (
                <ul className="absolute left-0 top-full mt-1 w-full bg-white text-gray-800 rounded-lg shadow-xl max-h-60 overflow-y-auto z-50 animate-fade-in border border-gray-200">
                   {filteredOptions.length === 0 ? (
                    <li className="p-3 text-sm text-gray-400 text-center italic">Nenhum supervisor encontrado</li>
                  ) : (
                    filteredOptions.map((sup) => (
                      <li 
                        key={sup}
                        onClick={() => handleSelectSupervisor(sup)}
                        className={`px-4 py-2 text-sm cursor-pointer hover:bg-blue-50 hover:text-blue-700 transition-colors border-b border-gray-50 last:border-none uppercase ${sup === selectedSupervisor ? 'bg-blue-100 text-blue-900 font-bold' : ''}`}
                      >
                        {sup}
                      </li>
                    ))
                  )}
                </ul>
              )}
            </div>
          </div>

          <div className="flex-1 flex flex-col justify-center">
            <div className="flex items-center bg-yellow-400 text-blue-900 p-3 px-6 font-bold justify-between border-b border-yellow-300/50">
              <span className="uppercase text-xs opacity-80">Total Clientes (Filtro)</span>
              <span className="text-xl">{totals.total}</span>
            </div>
            {/* Added rounding to bottom left for desktop */}
            <div className="flex items-center bg-blue-50 text-blue-900 p-3 px-6 font-bold justify-between md:rounded-bl-2xl">
              <span className="uppercase text-xs opacity-70">Representantes no Setor</span>
              <span className="text-lg">{activeRepsCount}</span>
            </div>
          </div>
        </div>

        {/* Right Side: Date & Actions */}
        {/* Added rounding to bottom right/top right based on breakpoint */}
        <div className="w-full md:w-80 bg-gray-50 p-6 flex flex-col justify-center border-l border-gray-200 rounded-b-2xl md:rounded-bl-none md:rounded-r-2xl">
          <div className="font-bold text-center mb-4 text-gray-500 uppercase text-xs tracking-wider">Período da Análise</div>

          <div className="space-y-3">
             <div className="flex justify-between items-center bg-white p-2 rounded-lg border border-gray-200 shadow-sm">
              <span className="font-bold text-gray-400 text-xs px-2">DE</span>
              <input 
                type="date" 
                value={startDate} 
                onChange={(e) => setStartDate(e.target.value)}
                className="text-right text-sm font-semibold text-gray-700 focus:outline-none bg-transparent"
              />
            </div>
            <div className="flex justify-between items-center bg-white p-2 rounded-lg border border-gray-200 shadow-sm">
              <span className="font-bold text-gray-400 text-xs px-2">ATÉ</span>
              <input 
                type="date" 
                value={endDate} 
                onChange={(e) => setEndDate(e.target.value)}
