          </div>

          <button 
            onClick={handleExport}
            className="mt-6 bg-green-600 hover:bg-green-700 text-white w-full py-3 rounded-xl text-sm font-bold flex justify-center items-center gap-2 shadow-md hover:shadow-lg transition-all"
          >
            <i className="fas fa-file-excel"></i> Exportar Dados
          </button>
        </div>
      </div>

      {/* Table - Virtualized */}
      <div 
        ref={containerRef}
        className="overflow-auto max-h-[600px] rounded-2xl shadow-lg border border-gray-200 relative"
      >
        <table className="w-full text-sm font-sans border-collapse">
          <thead className="sticky top-0 z-10 shadow-sm">
            <tr className="text-white">
              <th className="bg-blue-900 text-left p-4 w-1/3">Representante (Rep 3)</th>
              <th className="bg-green-600 text-center p-4">Ativo</th>
              <th className="bg-orange-400 text-center p-4">Semi-Ativo</th>
              <th className="bg-red-600 text-center p-4">Inativo</th>
              <th className="bg-gray-900 text-center p-4">Total Geral</th>
            </tr>
          </thead>
          <tbody>
            {tableData.length === 0 ? (
               <tr><td colSpan={5} className="p-8 text-center text-gray-500 bg-gray-50">Nenhum dado para este período</td></tr>
            ) : (
              <>
                {paddingTop > 0 && (
                  <tr style={{ height: `${paddingTop}px` }}>
                    <td colSpan={5} />
                  </tr>
                )}
                {virtualItems.map((index) => {
                  const row = tableData[index];
                  return (
                    <tr key={index} className="bg-white border-b border-gray-100 hover:bg-blue-50 transition-colors text-gray-800 h-[57px] box-border">
                      <td className="p-3 px-4 font-medium border-r border-gray-100">{row.representativeName}</td>

                      {/* Active Cell */}
                      <td className="p-3 px-4 text-center border-r border-gray-100">
                        {row.active > 0 ? (
                           <button 
                             onClick={() => onDrillDown({ rep: row.representativeName, supervisor: selectedSupervisor, status: ClientStatus.ACTIVE })}
                             className="px-3 py-1 rounded-full bg-green-100 text-green-800 font-bold text-xs hover:bg-green-200 transition-colors"
                           >
                             {row.active}
                           </button>
                        ) : <span className="text-gray-300">-</span>}
                      </td>

                      {/* Semi-Active Cell */}
                      <td className="p-3 px-4 text-center border-r border-gray-100">
                        {row.semiActive > 0 ? (
                           <button 
                            onClick={() => onDrillDown({ rep: row.representativeName, supervisor: selectedSupervisor, status: ClientStatus.SEMI_ACTIVE })}
                            className="px-3 py-1 rounded-full bg-orange-100 text-orange-800 font-bold text-xs hover:bg-orange-200 transition-colors"
                           >
                             {row.semiActive}
                           </button>
                        ) : <span className="text-gray-300">-</span>}
                      </td>

                      {/* Inactive Cell */}
                      <td className="p-3 px-4 text-center border-r border-gray-100">
                        {row.inactive > 0 ? (
                           <button 
                            onClick={() => onDrillDown({ rep: row.representativeName, supervisor: selectedSupervisor, status: ClientStatus.INACTIVE })}
                            className="px-3 py-1 rounded-full bg-red-100 text-red-800 font-bold text-xs hover:bg-red-200 transition-colors"
                           >
                             {row.inactive}
                           </button>
                        ) : <span className="text-gray-300">-</span>}
                      </td>

                      {/* Total Cell */}
                      <td className="p-3 px-4 text-center font-bold text-gray-700">
                        {row.total > 0 ? (
                          <button 
                            onClick={() => onDrillDown({ rep: row.representativeName, supervisor: selectedSupervisor })}
                            className="px-3 py-1 rounded-full bg-gray-200 text-gray-900 font-bold text-xs hover:bg-gray-300 transition-colors"
                          >
                            {row.total}
                          </button>
                        ) : 0}
                      </td>
                    </tr>
                  );
                })}
                {paddingBottom > 0 && (
                  <tr style={{ height: `${paddingBottom}px` }}>
                    <td colSpan={5} />
                  </tr>
                )}
              </>
            )}
          </tbody>
          <tfoot className="sticky bottom-0 z-10">
            <tr className="text-white font-bold text-center shadow-[0_-1px_3px_rgba(0,0,0,0.1)]">
              <td className="bg-blue-900 text-left p-4">Total Geral</td>
              <td 
                className="bg-green-600 p-4 cursor-pointer hover:bg-green-500 transition-colors"
                onClick={() => onDrillDown({ supervisor: selectedSupervisor, status: ClientStatus.ACTIVE })}
                title="Ver detalhes de Ativos"
              >
                {totals.active}
              </td>
              <td 
                className="bg-orange-500 p-4 cursor-pointer hover:bg-orange-400 transition-colors"
                onClick={() => onDrillDown({ supervisor: selectedSupervisor, status: ClientStatus.SEMI_ACTIVE })}
                title="Ver detalhes de Semi-ativos"
              >
                {totals.semi}
              </td>
              <td 
                className="bg-red-700 p-4 cursor-pointer hover:bg-red-600 transition-colors"
                onClick={() => onDrillDown({ supervisor: selectedSupervisor, status: ClientStatus.INACTIVE })}
                title="Ver detalhes de Inativos"
              >
                {totals.inactive}
              </td>
              <td 
                className="bg-gray-900 p-4 cursor-pointer hover:bg-gray-800 transition-colors"
                onClick={() => onDrillDown({ supervisor: selectedSupervisor })}
                title="Ver detalhes Geral"
              >
                {totals.total}
              </td>
            </tr>
          </tfoot>
        </table>
      </div>
    </div>
  );
};

export default SupervisorTab;

import React, { useState, useRef, useEffect } from 'react';
import RepresentativeTab from './components/RepresentativeTab';
import CityTab from './components/CityTab';
import SupervisorTab from './components/SupervisorTab';
import ClientListModal from './components/ClientListModal';
import { MOCK_DATA } from './services/mockData';
import { dbService } from './services/database'; 
import { githubService, GitHubConfig } from './services/githubService';
import { ClientRecord, ClientStatus } from './types';

type Tab = 'representative' | 'city' | 'supervisor';
type DataSource = 'MOCK' | 'LOCAL_DB';

const TAB_STORAGE_KEY = 'MILLENIUM_PREF_ACTIVE_TAB';
const GITHUB_CONFIG_KEY = 'MILLENIUM_GITHUB_CONFIG';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>(() => {
    return (localStorage.getItem(TAB_STORAGE_KEY) as Tab) || 'representative';
  });

  const [isLoading, setIsLoading] = useState(true);
  const [loadingMsg, setLoadingMsg] = useState('Processando...');
  const [clientData, setClientData] = useState<ClientRecord[]>([]);
  const [dataSource, setDataSource] = useState<DataSource>('MOCK');

  // GitHub Config State
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [ghConfig, setGhConfig] = useState<GitHubConfig>(() => {
    const saved = localStorage.getItem(GITHUB_CONFIG_KEY);
    return saved ? JSON.parse(saved) : {
      token: '',
      owner: '', 
      repo: '', 
      path: 'services/mockData.ts', // Caminho padrão
      branch: 'main'
    };
  });

  // Load Data on Startup
  useEffect(() => {
    const loadData = async () => {
      setIsLoading(true);
      setLoadingMsg('Carregando dados...');
      try {
        const dbData = await dbService.getAllClients();
        if (dbData && dbData.length > 0) {
          console.log(`Carregado ${dbData.length} registros do DB.`);
          setClientData(dbData);
          setDataSource('LOCAL_DB');
        } else {
          console.log("DB vazio, usando Mock.");
          setClientData(MOCK_DATA);
          setDataSource('MOCK');
        }
      } catch (error) {
        console.error("Erro DB:", error);
        setClientData(MOCK_DATA);
        setDataSource('MOCK');
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, []);

  useEffect(() => {
    localStorage.setItem(TAB_STORAGE_KEY, activeTab);
  }, [activeTab]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [modalOpen, setModalOpen] = useState(false);
  const [modalTitle, setModalTitle] = useState('');
  const [modalClients, setModalClients] = useState<ClientRecord[]>([]);

  // CSV Export
  const exportToCSV = (data: any[], filename: string) => {
    if (!data || !data.length) {
      alert("Sem dados para exportar.");
      return;
    }
    const headers = Object.keys(data[0]);
    const csvContent = [
      headers.join(';'),
      ...data.map(row => headers.map(fieldName => {
         let val = row[fieldName];
         if (val === null || val === undefined) val = '';
         val = String(val);
         if (val.includes('"') || val.includes(';')) val = `"${val.replace(/"/g, '""')}"`;
         return val;
      }).join(';'))
    ].join('\r\n');

    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `${filename}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Template Download
  const handleDownloadTemplate = () => {
    const headers = [
      "Código", "Razão Social / Nome", "Nome Fantasia", "CNPJ", "I. E.", 
      "Cidade", "UF", "Endereço (Logradouro)", "Número", "Bairro", "CEP", 
      "Ramo de atividade", "Grupo", "Ult. Compra", "Dias", "Cadastro", 
      "Representante Padrão", "Situação de bloqueio", "Situação do Cliente", 
      "Motivo de bloqueio", "pesquisa de ordem.Representante", "Representante Padrão - Copiar", 
      "Cidades", "Habitantes", "Rep", "rep2", "rep 3", "Supervisor"
    ];
    const exampleRow = [
      "4523", "CLIENTE EXEMPLO LTDA", "MERCADO EXEMPLO", "00.000.000/0001-00", 
      "123.456.789", "BAURU", "SP", "RUA EXEMPLO", "100", "CENTRO", 
      "17000-000", "SUPERMERCADO", "", "01/01/2024", "10", "01/01/2020", 
      "REP EXEMPLO", "Normal", "Ativo", "", "REP EXEMPLO", "REP EXEMPLO", 
      "BAURU - SP", "379297", "REP EXEMPLO", "REP EXEMPLO", "REP EXEMPLO", "SUPERVISAO GERAL"
    ];
    const csvContent = [headers.join(';'), exampleRow.join(';')].join('\r\n');
    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", "modelo_importacao.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- GITHUB INTEGRATION ---

  const handleSaveConfig = () => {
    localStorage.setItem(GITHUB_CONFIG_KEY, JSON.stringify(ghConfig));
    setShowConfigModal(false);
    alert('Configurações do GitHub salvas!');
  };

  const handleSyncToGitHub = async () => {
    if (!ghConfig.token || !ghConfig.owner || !ghConfig.repo) {
      alert("Configure os dados do GitHub primeiro (clique na engrenagem).");
      setShowConfigModal(true);
      return;
    }

    if (!clientData || clientData.length === 0) {
      alert("Sem dados para enviar.");
      return;
    }

    const confirmMsg = `Isso vai enviar ${clientData.length} registros para o arquivo '${ghConfig.path}' no GitHub.\n\nDeseja continuar?`;
    if (!confirm(confirmMsg)) return;

    setIsLoading(true);
    setLoadingMsg('Enviando dados para o GitHub...');

    try {
      // Create exact file content formatted as TypeScript
      const fileContent = `import { ClientRecord, ClientStatus } from '../types';

export const MOCK_DATA: ClientRecord[] = ${JSON.stringify(clientData, null, 2)};
`;

      await githubService.updateFile(
        ghConfig, 
        fileContent, 
        `Update mockData via Web App - ${new Date().toLocaleString()}`
      );

      alert('SUCESSO!\nOs dados foram salvos no GitHub.\nSe houver deploy automático (CI/CD), o site será atualizado em alguns minutos.');
    } catch (error: any) {
      console.error(error);
      alert(`ERRO: ${error.message}`);
    } finally {
      setIsLoading(false);
    }
  };

  // Import CSV
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    setLoadingMsg('Importando CSV...');

    const reader = new FileReader();
    reader.onload = async (e) => {
      const text = e.target?.result as string;
      if (!text) { setIsLoading(false); return; }

      try {
        const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
        // Check delimiter
        const firstLine = lines[0];
        const delimiter = firstLine.includes(';') ? ';' : ',';

        const dataLines = lines.slice(1);

        const newRecords: ClientRecord[] = dataLines.map((line, index) => {
          const cols = line.split(delimiter);
          if (cols.length < 5) return null;

          const clean = (val: string) => val ? val.replace(/"/g, '').trim() : '';

          const statusRaw = clean(cols[18]);
          let status = ClientStatus.ACTIVE;
          if (statusRaw === 'Semi-ativo') status = ClientStatus.SEMI_ACTIVE;
          if (statusRaw === 'Inativo') status = ClientStatus.INACTIVE;

          const parseDate = (d: string) => {
            const c = clean(d);
            const parts = c.split('/');
            if (parts.length === 3) return `${parts[2]}-${parts[1]}-${parts[0]}`;
            return c.includes('-') ? c : new Date().toISOString().split('T')[0];
          };

          const standardRep = clean(cols[24]) || clean(cols[20]) || 'Indefinido';
          const rep3 = clean(cols[26]) || standardRep;
          const supervisor = clean(cols[27]) || 'GERAL';

          return {
            id: clean(cols[0]) || `IMP-${index}`,
            socialName: clean(cols[1]),
            fantasyName: clean(cols[2]),
            cnpj: clean(cols[3]),
            ie: clean(cols[4]),
            city: clean(cols[5]),
            state: clean(cols[6]),
            address: `${clean(cols[7])}, ${clean(cols[8])}`,
            neighborhood: clean(cols[9]),
            cep: clean(cols[10]),
            activity: clean(cols[11]),
            group: clean(cols[12]),
            lastPurchaseDate: parseDate(cols[13]),
            daysSincePurchase: parseInt(clean(cols[14]).replace(/\D/g, '') || '0', 10),
            registerDate: parseDate(cols[15]),
            representativeName: standardRep,
            population: parseInt(clean(cols[23]).replace(/\D/g, '') || '0', 10),
            status: status,
            rep3: rep3, 
            supervisor: supervisor
          };
        }).filter(r => r !== null) as ClientRecord[];

        if (newRecords.length > 0) {
          // Save to DB
          await dbService.saveClients(newRecords);
          setClientData(newRecords);
          setDataSource('LOCAL_DB');
          alert(`${newRecords.length} registros importados!\n\nPara tornar esses dados permanentes para todos, configure o GitHub e clique em 'Salvar no GitHub'.`);
        } else {
          alert('Arquivo vazio ou formato incorreto.');
        }
      } catch (err) {
        console.error(err);
        alert('Erro ao processar arquivo. Verifique se é um CSV válido.');
      } finally {
        setIsLoading(false);
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  const handleResetData = async () => {
    if (confirm("Deseja apagar os dados importados e voltar ao padrão do sistema?")) {
      setIsLoading(true);
      await dbService.clearDB();
      localStorage.clear(); 
      window.location.reload();
    }
  };

  const handleDrillDown = (filters: any) => {
    let filtered = clientData;
    if (filters.rep) filtered = filtered.filter(c => c.rep3 === filters.rep);
    if (filters.city) filtered = filtered.filter(c => c.city === filters.city);
    if (filters.supervisor) filtered = filtered.filter(c => c.supervisor === filters.supervisor);
    if (filters.status) {
      if (Array.isArray(filters.status)) filtered = filtered.filter(c => (filters.status as any).includes(c.status));
      else filtered = filtered.filter(c => c.status === filters.status);
    }

    let titleParts = [];
    if (filters.rep) titleParts.push(`Rep: ${filters.rep}`);
    if (filters.supervisor) titleParts.push(`Sup: ${filters.supervisor}`);
    if (filters.city) titleParts.push(`Cidade: ${filters.city}`);
    setModalTitle(`Detalhes - ${titleParts.join(' | ')}`);
    setModalClients(filtered);
    setModalOpen(true);
  };

  return (
    <div className="min-h-screen bg-gray-100 font-sans text-gray-800">

      {/* Top Status Bar */}
      <div className={`w-full py-1 text-center text-xs font-bold uppercase tracking-wider text-white flex justify-center items-center gap-4 ${dataSource === 'LOCAL_DB' ? 'bg-green-600' : 'bg-gray-500'}`}>
        <span>
          {dataSource === 'LOCAL_DB' 
            ? <><i className="fas fa-database mr-2"></i> Usando Dados Locais</> 
            : <><i className="fas fa-file-code mr-2"></i> Usando Dados Padrão</>}
        </span>
      </div>

      {isLoading && (
        <div className="fixed inset-0 bg-black/50 z-[100] flex items-center justify-center backdrop-blur-sm">
           <div className="bg-white p-6 rounded-2xl shadow-2xl flex flex-col items-center">
             <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-900 mb-4"></div>
             <p className="text-blue-900 font-bold">{loadingMsg}</p>
           </div>
        </div>
      )}

      {/* GitHub Config Modal */}
      {showConfigModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[90] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-fade-in">
            <div className="bg-gray-900 text-white p-4 font-bold flex justify-between items-center">
              <span><i className="fab fa-github mr-2"></i> Configurar Integração GitHub</span>
              <button onClick={() => setShowConfigModal(false)}><i className="fas fa-times"></i></button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Usuário / Owner</label>
                <input 
                  type="text" 
                  value={ghConfig.owner} 
                  onChange={e => setGhConfig({...ghConfig, owner: e.target.value})}
                  className="w-full border p-2 rounded" placeholder="Ex: seu-usuario"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Repositório</label>
                <input 
                  type="text" 
                  value={ghConfig.repo} 
                  onChange={e => setGhConfig({...ghConfig, repo: e.target.value})}
                  className="w-full border p-2 rounded" placeholder="Ex: millenium-dashboard"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Caminho do Arquivo (Mock Data)</label>
                <input 
                  type="text" 
                  value={ghConfig.path} 
                  onChange={e => setGhConfig({...ghConfig, path: e.target.value})}
                  className="w-full border p-2 rounded bg-gray-50" placeholder="services/mockData.ts"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Personal Access Token</label>
                <input 
                  type="password" 
                  value={ghConfig.token} 
                  onChange={e => setGhConfig({...ghConfig, token: e.target.value})}
                  className="w-full border p-2 rounded" placeholder="ghp_xxxxxxxxxxxx"
                />
                <p className="text-[10px] text-gray-400 mt-1">
                  O token precisa da permissão "repo" ou "contents:write".
                </p>
              </div>
              <button onClick={handleSaveConfig} className="w-full bg-blue-600 text-white py-2 rounded font-bold hover:bg-blue-700">
                Salvar Configuração
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="p-4 md:p-6">
        <div className="max-w-6xl mx-auto bg-white shadow-2xl rounded-3xl overflow-hidden border border-gray-100">

          <div className="bg-gradient-to-r from-blue-900 to-blue-800 text-white p-6 rounded-t-3xl">
            <div className="flex flex-col md:flex-row justify-between items-center gap-6">
              <div>
                <h1 className="text-3xl font-bold tracking-tight flex items-center gap-3">
                  <i className="fas fa-chart-pie"></i>
                  Curva ABC
                </h1>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-blue-200 text-sm font-medium tracking-wide">Millenium Utilidades</span>
                </div>
              </div>

              <div className="flex flex-wrap justify-center gap-2 items-center">
                <button onClick={handleDownloadTemplate} className="bg-white/10 hover:bg-white/20 text-white px-3 py-2 rounded-lg text-xs font-semibold flex items-center gap-2 border border-white/20">
                  <i className="fas fa-download"></i> Modelo
                </button>

                <div className="relative">
                  <input type="file" accept=".csv" ref={fileInputRef} onChange={handleFileUpload} className="hidden" />
                  <button onClick={() => fileInputRef.current?.click()} className="bg-yellow-400 hover:bg-yellow-300 text-blue-900 px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 shadow-lg">
                    <i className="fas fa-file-import"></i> Importar CSV
                  </button>
                </div>

                <div className="h-8 w-px bg-white/20 mx-1"></div>

                 {/* Config Button */}
                 <button 
                  onClick={() => setShowConfigModal(true)}
                  className="bg-gray-700 hover:bg-gray-600 text-white w-9 h-9 rounded-lg flex items-center justify-center transition-all border border-gray-600"
                  title="Configurar GitHub"
                >
                  <i className="fas fa-cog"></i>
                </button>

                {/* GitHub Sync Button */}
                <button 
                  onClick={handleSyncToGitHub} 
                  className="bg-black hover:bg-gray-900 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-md flex items-center gap-2 border border-gray-700 hover:border-gray-500 transition-all" 
                  title="Enviar dados atuais para o GitHub (Atualiza o site)"
                >
                  <i className="fab fa-github"></i> Salvar no GitHub
                </button>

                <button onClick={handleResetData} className="bg-red-500/80 hover:bg-red-500 text-white px-3 py-2 rounded-lg text-xs font-bold shadow-sm" title="Resetar">
                  <i className="fas fa-trash"></i>
                </button>
              </div>
            </div>
          </div>

          <div className="flex flex-wrap border-b border-gray-200 bg-gray-50/50 p-2 gap-2">
            {[
              { id: 'representative', icon: 'fa-user-tie', label: 'Representante' },
              { id: 'city', icon: 'fa-city', label: 'Cidade' },
              { id: 'supervisor', icon: 'fa-user-shield', label: 'Supervisor' }
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as Tab)}
                className={`flex-1 py-3 px-4 rounded-xl text-center font-bold text-sm transition-all duration-200 ${
                  activeTab === tab.id
                    ? 'bg-white text-blue-900 shadow-md ring-1 ring-black/5'
                    : 'text-gray-500 hover:text-blue-700 hover:bg-gray-100'
                }`}
              >
                <i className={`fas ${tab.icon} mr-2`}></i> {tab.label}
              </button>
            ))}
          </div>

          <div className="p-6 md:p-8 bg-white min-h-[500px]">
            {activeTab === 'representative' ? (
              <RepresentativeTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} />
            ) : activeTab === 'city' ? (
              <CityTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} />
            ) : (
              <SupervisorTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} />
            )}
          </div>

          <div className="bg-gray-50 p-4 text-center text-xs text-gray-400 border-t border-gray-100">
            &copy; {new Date().getFullYear()} Millenium Utilidades.
          </div>
        </div>
        <ClientListModal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={modalTitle} clients={modalClients} />
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import RepresentativeTab from './components/RepresentativeTab';
import CityTab from './components/CityTab';
import SupervisorTab from './components/SupervisorTab';
import ClientListModal from './components/ClientListModal';
import { MOCK_DATA } from './services/mockData';
import { dbService } from './services/database'; 
import { githubService, GitHubConfig } from './services/githubService';
import { ClientRecord, ClientStatus } from './types';

type Tab = 'representative' | 'city' | 'supervisor';
type DataSource = 'MOCK' | 'LOCAL_DB';

const TAB_STORAGE_KEY = 'MILLENIUM_PREF_ACTIVE_TAB';
const GITHUB_CONFIG_KEY = 'MILLENIUM_GITHUB_CONFIG';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>(() => {
    return (localStorage.getItem(TAB_STORAGE_KEY) as Tab) || 'representative';
  });

  const [isLoading, setIsLoading] = useState(true);
  const [loadingMsg, setLoadingMsg] = useState('Processando...');
  const [clientData, setClientData] = useState<ClientRecord[]>([]);
  const [dataSource, setDataSource] = useState<DataSource>('MOCK');

  // GitHub Config State
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [ghConfig, setGhConfig] = useState<GitHubConfig>(() => {
    const saved = localStorage.getItem(GITHUB_CONFIG_KEY);
    return saved ? JSON.parse(saved) : {
      token: '',
      owner: '', 
      repo: '', 
      path: 'services/mockData.ts', // Caminho padrão
      branch: 'main'
    };
  });

  // Load Data on Startup
  useEffect(() => {
    const loadData = async () => {
      setIsLoading(true);
      setLoadingMsg('Carregando dados...');
      try {
        const dbData = await dbService.getAllClients();
        if (dbData && dbData.length > 0) {
          console.log(`Carregado ${dbData.length} registros do DB.`);
          setClientData(dbData);
          setDataSource('LOCAL_DB');
        } else {
          console.log("DB vazio, usando Mock.");
          setClientData(MOCK_DATA);
          setDataSource('MOCK');
        }
      } catch (error) {
        console.error("Erro DB:", error);
        setClientData(MOCK_DATA);
        setDataSource('MOCK');
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, []);

  useEffect(() => {
    localStorage.setItem(TAB_STORAGE_KEY, activeTab);
  }, [activeTab]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [modalOpen, setModalOpen] = useState(false);
  const [modalTitle, setModalTitle] = useState('');
  const [modalClients, setModalClients] = useState<ClientRecord[]>([]);

  // CSV Export
  const exportToCSV = (data: any[], filename: string) => {
    if (!data || !data.length) {
      alert("Sem dados para exportar.");
      return;
    }
    const headers = Object.keys(data[0]);
    const csvContent = [
      headers.join(';'),
      ...data.map(row => headers.map(fieldName => {
         let val = row[fieldName];
         if (val === null || val === undefined) val = '';
         val = String(val);
         if (val.includes('"') || val.includes(';')) val = `"${val.replace(/"/g, '""')}"`;
         return val;
      }).join(';'))
    ].join('\r\n');

    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `${filename}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Template Download
  const handleDownloadTemplate = () => {
    const headers = [
      "Código", "Razão Social / Nome", "Nome Fantasia", "CNPJ", "I. E.", 
      "Cidade", "UF", "Endereço (Logradouro)", "Número", "Bairro", "CEP", 
      "Ramo de atividade", "Grupo", "Ult. Compra", "Dias", "Cadastro", 
      "Representante Padrão", "Situação de bloqueio", "Situação do Cliente", 
      "Motivo de bloqueio", "pesquisa de ordem.Representante", "Representante Padrão - Copiar", 
      "Cidades", "Habitantes", "Rep", "rep2", "rep 3", "Supervisor"
    ];
    const exampleRow = [
      "4523", "CLIENTE EXEMPLO LTDA", "MERCADO EXEMPLO", "00.000.000/0001-00", 
      "123.456.789", "BAURU", "SP", "RUA EXEMPLO", "100", "CENTRO", 
      "17000-000", "SUPERMERCADO", "", "01/01/2024", "10", "01/01/2020", 
      "REP EXEMPLO", "Normal", "Ativo", "", "REP EXEMPLO", "REP EXEMPLO", 
      "BAURU - SP", "379297", "REP EXEMPLO", "REP EXEMPLO", "REP EXEMPLO", "SUPERVISAO GERAL"
    ];
    const csvContent = [headers.join(';'), exampleRow.join(';')].join('\r\n');
    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", "modelo_importacao.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- GITHUB INTEGRATION ---

  const handleSaveConfig = () => {
    localStorage.setItem(GITHUB_CONFIG_KEY, JSON.stringify(ghConfig));
    setShowConfigModal(false);
    alert('Configurações do GitHub salvas!');
  };

  // Import CSV & Auto-Sync
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    setLoadingMsg('Importando CSV...');

    const reader = new FileReader();
    reader.onload = async (e) => {
      const text = e.target?.result as string;
      if (!text) { setIsLoading(false); return; }

      try {
        const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
        // Check delimiter
        const firstLine = lines[0];
        const delimiter = firstLine.includes(';') ? ';' : ',';

        const dataLines = lines.slice(1);

        const newRecords: ClientRecord[] = dataLines.map((line, index) => {
          const cols = line.split(delimiter);
          if (cols.length < 5) return null;

          const clean = (val: string) => val ? val.replace(/"/g, '').trim() : '';

          const statusRaw = clean(cols[18]);
          let status = ClientStatus.ACTIVE;
          if (statusRaw === 'Semi-ativo') status = ClientStatus.SEMI_ACTIVE;
          if (statusRaw === 'Inativo') status = ClientStatus.INACTIVE;

          const parseDate = (d: string) => {
            const c = clean(d);
            const parts = c.split('/');
            if (parts.length === 3) return `${parts[2]}-${parts[1]}-${parts[0]}`;
            return c.includes('-') ? c : new Date().toISOString().split('T')[0];
          };

          const standardRep = clean(cols[24]) || clean(cols[20]) || 'Indefinido';
          const rep3 = clean(cols[26]) || standardRep;
          const supervisor = clean(cols[27]) || 'GERAL';

          return {
            id: clean(cols[0]) || `IMP-${index}`,
            socialName: clean(cols[1]),
            fantasyName: clean(cols[2]),
            cnpj: clean(cols[3]),
            ie: clean(cols[4]),
            city: clean(cols[5]),
            state: clean(cols[6]),
            address: `${clean(cols[7])}, ${clean(cols[8])}`,
            neighborhood: clean(cols[9]),
            cep: clean(cols[10]),
            activity: clean(cols[11]),
            group: clean(cols[12]),
            lastPurchaseDate: parseDate(cols[13]),
            daysSincePurchase: parseInt(clean(cols[14]).replace(/\D/g, '') || '0', 10),
            registerDate: parseDate(cols[15]),
            representativeName: standardRep,
            population: parseInt(clean(cols[23]).replace(/\D/g, '') || '0', 10),
            status: status,
            rep3: rep3, 
            supervisor: supervisor
          };
        }).filter(r => r !== null) as ClientRecord[];

        if (newRecords.length > 0) {
          // 1. Save to Local DB
          await dbService.saveClients(newRecords);
          setClientData(newRecords);
          setDataSource('LOCAL_DB');

          let successMessage = `${newRecords.length} registros importados e salvos localmente!`;

          // 2. Auto-Sync to GitHub if Configured
          if (ghConfig.token && ghConfig.owner && ghConfig.repo) {
             setLoadingMsg('Sincronizando com GitHub...');
             try {
                const fileContent = `import { ClientRecord, ClientStatus } from '../types';

export const MOCK_DATA: ClientRecord[] = ${JSON.stringify(newRecords, null, 2)};
`;
                await githubService.updateFile(
                  ghConfig, 
                  fileContent, 
                  `Auto Update via Import - ${new Date().toLocaleString()}`
                );
                successMessage += `\n\nSUCESSO: O código no GitHub também foi atualizado automaticamente!`;
             } catch (ghError: any) {
                console.error(ghError);
                successMessage += `\n\nAVISO: Falha ao atualizar GitHub. Erro: ${ghError.message}`;
             }
          } else {
             successMessage += `\n\n(GitHub não configurado: dados apenas locais)`;
          }

          alert(successMessage);

        } else {
          alert('Arquivo vazio ou formato incorreto.');
        }
      } catch (err) {
        console.error(err);
        alert('Erro ao processar arquivo. Verifique se é um CSV válido.');
      } finally {
        setIsLoading(false);
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  const handleResetData = async () => {
    if (confirm("Deseja apagar os dados importados e voltar ao padrão do sistema?")) {
      setIsLoading(true);
      await dbService.clearDB();
      localStorage.clear(); 
      window.location.reload();
    }
  };

  const handleDrillDown = (filters: any) => {
    let filtered = clientData;
    if (filters.rep) filtered = filtered.filter(c => c.rep3 === filters.rep);
    if (filters.city) filtered = filtered.filter(c => c.city === filters.city);
    if (filters.supervisor) filtered = filtered.filter(c => c.supervisor === filters.supervisor);
    if (filters.status) {
      if (Array.isArray(filters.status)) filtered = filtered.filter(c => (filters.status as any).includes(c.status));
      else filtered = filtered.filter(c => c.status === filters.status);
    }

    let titleParts = [];
    if (filters.rep) titleParts.push(`Rep: ${filters.rep}`);
    if (filters.supervisor) titleParts.push(`Sup: ${filters.supervisor}`);
    if (filters.city) titleParts.push(`Cidade: ${filters.city}`);
    setModalTitle(`Detalhes - ${titleParts.join(' | ')}`);
    setModalClients(filtered);
    setModalOpen(true);
  };

  return (
    <div className="min-h-screen bg-gray-100 font-sans text-gray-800">

      {/* Top Status Bar */}
      <div className={`w-full py-1 text-center text-xs font-bold uppercase tracking-wider text-white flex justify-center items-center gap-4 ${dataSource === 'LOCAL_DB' ? 'bg-green-600' : 'bg-gray-500'}`}>
        <span>
          {dataSource === 'LOCAL_DB' 
            ? <><i className="fas fa-database mr-2"></i> Usando Dados Locais</> 
            : <><i className="fas fa-file-code mr-2"></i> Usando Dados Padrão</>}
        </span>
      </div>

      {isLoading && (
        <div className="fixed inset-0 bg-black/50 z-[100] flex items-center justify-center backdrop-blur-sm">
           <div className="bg-white p-6 rounded-2xl shadow-2xl flex flex-col items-center">
             <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-900 mb-4"></div>
             <p className="text-blue-900 font-bold">{loadingMsg}</p>
           </div>
        </div>
      )}

      {/* GitHub Config Modal */}
      {showConfigModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[90] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-fade-in">
            <div className="bg-gray-900 text-white p-4 font-bold flex justify-between items-center">
              <span><i className="fab fa-github mr-2"></i> Configurar Integração GitHub</span>
              <button onClick={() => setShowConfigModal(false)}><i className="fas fa-times"></i></button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Usuário / Owner</label>
                <input 
                  type="text" 
                  value={ghConfig.owner} 
                  onChange={e => setGhConfig({...ghConfig, owner: e.target.value})}
                  className="w-full border p-2 rounded" placeholder="Ex: seu-usuario"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Repositório</label>
                <input 
                  type="text" 
                  value={ghConfig.repo} 
                  onChange={e => setGhConfig({...ghConfig, repo: e.target.value})}
                  className="w-full border p-2 rounded" placeholder="Ex: millenium-dashboard"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Caminho do Arquivo (Mock Data)</label>
                <input 
                  type="text" 
                  value={ghConfig.path} 
                  onChange={e => setGhConfig({...ghConfig, path: e.target.value})}
                  className="w-full border p-2 rounded bg-gray-50" placeholder="services/mockData.ts"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Personal Access Token</label>
                <input 
                  type="password" 
                  value={ghConfig.token} 
                  onChange={e => setGhConfig({...ghConfig, token: e.target.value})}
                  className="w-full border p-2 rounded" placeholder="ghp_xxxxxxxxxxxx"
                />
                <p className="text-[10px] text-gray-400 mt-1">
                  O token precisa da permissão "repo" ou "contents:write".
                </p>
              </div>
              <button onClick={handleSaveConfig} className="w-full bg-blue-600 text-white py-2 rounded font-bold hover:bg-blue-700">
                Salvar Configuração
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="p-4 md:p-6">
        <div className="max-w-6xl mx-auto bg-white shadow-2xl rounded-3xl overflow-hidden border border-gray-100">

          <div className="bg-gradient-to-r from-blue-900 to-blue-800 text-white p-6 rounded-t-3xl">
            <div className="flex flex-col md:flex-row justify-between items-center gap-6">
              <div>
                <h1 className="text-3xl font-bold tracking-tight flex items-center gap-3">
                  <i className="fas fa-chart-pie"></i>
                  Curva ABC
                </h1>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-blue-200 text-sm font-medium tracking-wide">Millenium Utilidades</span>
                </div>
              </div>

              <div className="flex flex-wrap justify-center gap-2 items-center">
                <button onClick={handleDownloadTemplate} className="bg-white/10 hover:bg-white/20 text-white px-3 py-2 rounded-lg text-xs font-semibold flex items-center gap-2 border border-white/20">
                  <i className="fas fa-download"></i> Modelo
                </button>

                <div className="relative">
                  <input type="file" accept=".csv" ref={fileInputRef} onChange={handleFileUpload} className="hidden" />
                  <button onClick={() => fileInputRef.current?.click()} className="bg-yellow-400 hover:bg-yellow-300 text-blue-900 px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 shadow-lg">
                    <i className="fas fa-file-import"></i> Importar CSV
                  </button>
                </div>

                <div className="h-8 w-px bg-white/20 mx-1"></div>

                 {/* Config Button */}
                 <button 
                  onClick={() => setShowConfigModal(true)}
                  className="bg-gray-700 hover:bg-gray-600 text-white w-9 h-9 rounded-lg flex items-center justify-center transition-all border border-gray-600"
                  title="Configurar GitHub"
                >
                  <i className="fas fa-cog"></i>
                </button>

                <button onClick={handleResetData} className="bg-red-500/80 hover:bg-red-500 text-white px-3 py-2 rounded-lg text-xs font-bold shadow-sm" title="Resetar">
                  <i className="fas fa-trash"></i>
                </button>
              </div>
            </div>
          </div>

          <div className="flex flex-wrap border-b border-gray-200 bg-gray-50/50 p-2 gap-2">
            {[
              { id: 'representative', icon: 'fa-user-tie', label: 'Representante' },
              { id: 'city', icon: 'fa-city', label: 'Cidade' },
              { id: 'supervisor', icon: 'fa-user-shield', label: 'Supervisor' }
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as Tab)}
                className={`flex-1 py-3 px-4 rounded-xl text-center font-bold text-sm transition-all duration-200 ${
                  activeTab === tab.id
                    ? 'bg-white text-blue-900 shadow-md ring-1 ring-black/5'
                    : 'text-gray-500 hover:text-blue-700 hover:bg-gray-100'
