import React, { useState, useMemo, useRef, useEffect } from 'react';
import { ClientRecord, CityViewRow, ClientStatus } from '../types';
import { useVirtualizer } from '../hooks/useVirtualizer';

interface SupervisorTabProps {
  data: ClientRecord[];
  onExport: (data: any[], filename: string) => void;
  onDrillDown: (filters: { rep?: string; city?: string; status?: ClientStatus | ClientStatus[]; supervisor?: string }) => void;
}

const ITEM_HEIGHT = 57; // Estimated row height

// Persistence Keys
const KEY_SUP_NAME = 'MILLENIUM_PREF_SUP_NAME';
const KEY_DATE_START = 'MILLENIUM_PREF_DATE_START';
const KEY_DATE_END = 'MILLENIUM_PREF_DATE_END';

const SupervisorTab: React.FC<SupervisorTabProps> = ({ data, onExport, onDrillDown }) => {
  // Initialize from LocalStorage
  const [selectedSupervisor, setSelectedSupervisor] = useState<string>(() => localStorage.getItem(KEY_SUP_NAME) || '');
  const [startDate, setStartDate] = useState(() => localStorage.getItem(KEY_DATE_START) || '2022-01-01');
  const [endDate, setEndDate] = useState(() => localStorage.getItem(KEY_DATE_END) || new Date().toISOString().split('T')[0]);

  // Persist Changes
  useEffect(() => { if (selectedSupervisor) localStorage.setItem(KEY_SUP_NAME, selectedSupervisor); }, [selectedSupervisor]);
  useEffect(() => { localStorage.setItem(KEY_DATE_START, startDate); }, [startDate]);
  useEffect(() => { localStorage.setItem(KEY_DATE_END, endDate); }, [endDate]);

  // Searchable Select States
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState(selectedSupervisor);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Sync SearchTerm
  useEffect(() => { if (selectedSupervisor) setSearchTerm(selectedSupervisor); }, [selectedSupervisor]);

  // Extract unique Supervisors
  const supervisors = useMemo(() => 
    Array.from(new Set(data.map(d => d.supervisor))).sort(),
  [data]);

  // Set default supervisor if empty
  useEffect(() => {
    if (supervisors.length > 0) {
      if (!selectedSupervisor || !supervisors.includes(selectedSupervisor)) {
        const initial = supervisors[0];
        setSelectedSupervisor(initial);
        setSearchTerm(initial);
      }
    }
  }, [supervisors, selectedSupervisor]);

  // Handle clicking outside to close dropdown
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsDropdownOpen(false);
        // Revert to selectedSupervisor if invalid
        if (!supervisors.includes(searchTerm) && searchTerm !== '') {
           setSearchTerm(selectedSupervisor);
        } else if (searchTerm === '') {
           setSearchTerm(selectedSupervisor);
        }
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [dropdownRef, selectedSupervisor, searchTerm, supervisors]);

  // Filtered Options
  const filteredOptions = useMemo(() => {
    if (!searchTerm) return supervisors;
    return supervisors.filter(s => 
      s.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [supervisors, searchTerm]);

  const handleSelectSupervisor = (sup: string) => {
    setSelectedSupervisor(sup);
    setSearchTerm(sup);
    setIsDropdownOpen(false);
  };

  const handleClearFilters = () => {
    // Reset Dates
    setStartDate('2022-01-01');
    setEndDate(new Date().toISOString().split('T')[0]);

    // Reset Supervisor to first available
    if (supervisors.length > 0) {
      const initial = supervisors[0];
      setSelectedSupervisor(initial);
      setSearchTerm(initial);
    } else {
      setSelectedSupervisor('');
      setSearchTerm('');
    }
  };

  // Filter and Aggregate Data
  const tableData = useMemo(() => {
    if (!selectedSupervisor) return [];

    // 1. Filter by Supervisor and Date
    const filtered = data.filter(item => {
      const matchSup = item.supervisor === selectedSupervisor;
      const matchDate = item.lastPurchaseDate >= startDate && item.lastPurchaseDate <= endDate;
      return matchSup && matchDate;
    });

    // 2. Group by Representative (Using rep3 now)
    const repMap = new Map<string, CityViewRow>();

    filtered.forEach(item => {
      // Use rep3 for grouping
      const repKey = item.rep3;

      if (!repMap.has(repKey)) {
        repMap.set(repKey, {
          representativeName: repKey,
          active: 0,
          semiActive: 0,
          inactive: 0,
          total: 0
        });
      }
      const entry = repMap.get(repKey)!;

      if (item.status === ClientStatus.ACTIVE) entry.active++;
      else if (item.status === ClientStatus.SEMI_ACTIVE) entry.semiActive++;
      else if (item.status === ClientStatus.INACTIVE) entry.inactive++;

      entry.total++;
    });

    return Array.from(repMap.values()).sort((a, b) => a.representativeName.localeCompare(b.representativeName));
  }, [selectedSupervisor, startDate, endDate, data]);

  // Totals
  const totals = tableData.reduce((acc, curr) => ({
    active: acc.active + curr.active,
    semi: acc.semi + curr.semiActive,
    inactive: acc.inactive + curr.inactive,
    total: acc.total + curr.total
  }), { active: 0, semi: 0, inactive: 0, total: 0 });

  const activeRepsCount = tableData.length;

  const handleExport = () => {
    const csvData = tableData.map(row => ({
      'Supervisor': selectedSupervisor,
      'Representante': row.representativeName,
      'Ativo': row.active,
      'Semi-ativo': row.semiActive,
      'Inativo': row.inactive,
      'Total Geral': row.total
    }));
    onExport(csvData, `Status_Supervisor_${selectedSupervisor}_${startDate}_${endDate}`);
  };

  // Virtualization
  const { virtualItems, paddingTop, paddingBottom } = useVirtualizer({
    count: tableData.length,
    itemHeight: ITEM_HEIGHT,
    containerRef: containerRef,
    overscan: 5
  });

  return (
    <div className="flex flex-col gap-6">
       {/* Header / Filters Container */}
       {/* Removed overflow-hidden and added specific rounding to children to allow dropdown overflow */}
       <div className="flex flex-col md:flex-row gap-0 border border-gray-200 shadow-lg rounded-2xl relative z-20">

        {/* Left Side: Info Panel */}
        <div className="flex-1 flex flex-col">
          {/* Supervisor Select - Searchable */}
          {/* Added rounding to top left/right based on breakpoint */}
          <div className="flex items-center bg-blue-900 text-white p-4 relative rounded-t-2xl md:rounded-tr-none md:rounded-tl-2xl" ref={dropdownRef}>
            <span className="font-bold w-32 text-blue-200 shrink-0">Setor / Sup.</span>
            <div className="flex-1 relative group">
              <input 
                type="text"
                value={searchTerm}
                onChange={(e) => {
                  setSearchTerm(e.target.value);
                  setIsDropdownOpen(true);
                }}
                onClick={() => setIsDropdownOpen(true)}
                placeholder="Buscar supervisor..."
                className="w-full bg-blue-800/50 text-white border border-blue-700 rounded-lg text-sm p-2 pr-8 focus:outline-none focus:ring-2 focus:ring-blue-400 placeholder-blue-300 font-bold uppercase"
              />
               <div 
                className="absolute inset-y-0 right-0 flex items-center px-2 cursor-pointer text-blue-300 hover:text-white"
                onClick={() => setIsDropdownOpen(!isDropdownOpen)}
              >
                <i className={`fas fa-chevron-down text-xs transition-transform duration-200 ${isDropdownOpen ? 'transform rotate-180' : ''}`}></i>
              </div>

              {/* Dropdown List */}
              {isDropdownOpen && (
                <ul className="absolute left-0 top-full mt-1 w-full bg-white text-gray-800 rounded-lg shadow-xl max-h-60 overflow-y-auto z-50 animate-fade-in border border-gray-200">
                   {filteredOptions.length === 0 ? (
                    <li className="p-3 text-sm text-gray-400 text-center italic">Nenhum supervisor encontrado</li>
                  ) : (
                    filteredOptions.map((sup) => (
                      <li 
                        key={sup}
                        onClick={() => handleSelectSupervisor(sup)}
                        className={`px-4 py-2 text-sm cursor-pointer hover:bg-blue-50 hover:text-blue-700 transition-colors border-b border-gray-50 last:border-none uppercase ${sup === selectedSupervisor ? 'bg-blue-100 text-blue-900 font-bold' : ''}`}
                      >
                        {sup}
                      </li>
                    ))
                  )}
                </ul>
              )}
            </div>
          </div>

          <div className="flex-1 flex flex-col justify-center">
            <div className="flex items-center bg-yellow-400 text-blue-900 p-3 px-6 font-bold justify-between border-b border-yellow-300/50">
              <span className="uppercase text-xs opacity-80">Total Clientes (Filtro)</span>
              <span className="text-xl">{totals.total}</span>
            </div>
            {/* Added rounding to bottom left for desktop */}
            <div className="flex items-center bg-blue-50 text-blue-900 p-3 px-6 font-bold justify-between md:rounded-bl-2xl">
              <span className="uppercase text-xs opacity-70">Representantes no Setor</span>
              <span className="text-lg">{activeRepsCount}</span>
            </div>
          </div>
        </div>

        {/* Right Side: Date & Actions */}
        {/* Added rounding to bottom right/top right based on breakpoint */}
        <div className="w-full md:w-80 bg-gray-50 p-6 flex flex-col justify-center border-l border-gray-200 rounded-b-2xl md:rounded-bl-none md:rounded-r-2xl">
          <div className="font-bold text-center mb-4 text-gray-500 uppercase text-xs tracking-wider">Período da Análise</div>

          <div className="space-y-3">
             <div className="flex justify-between items-center bg-white p-2 rounded-lg border border-gray-200 shadow-sm">
              <span className="font-bold text-gray-400 text-xs px-2">DE</span>
              <input 
                type="date" 
                value={startDate} 
                onChange={(e) => setStartDate(e.target.value)}
                className="text-right text-sm font-semibold text-gray-700 focus:outline-none bg-transparent"
              />
            </div>
            <div className="flex justify-between items-center bg-white p-2 rounded-lg border border-gray-200 shadow-sm">
              <span className="font-bold text-gray-400 text-xs px-2">ATÉ</span>
              <input 
                type="date" 
                value={endDate} 
                onChange={(e) => setEndDate(e.target.value)}
                className="text-right text-sm font-semibold text-gray-700 focus:outline-none bg-transparent"
              />
            </div>
          </div>

          <button 
            onClick={handleClearFilters}
            className="mt-4 bg-gray-200 hover:bg-gray-300 text-gray-600 w-full py-2.5 rounded-xl text-sm font-bold flex justify-center items-center gap-2 shadow-sm transition-all"
          >
            <i className="fas fa-eraser"></i> Limpar Filtros
          </button>

          <button 
            onClick={handleExport}
            className="mt-2 bg-green-600 hover:bg-green-700 text-white w-full py-3 rounded-xl text-sm font-bold flex justify-center items-center gap-2 shadow-md hover:shadow-lg transition-all"
          >
            <i className="fas fa-file-excel"></i> Exportar Dados
          </button>
        </div>
      </div>

      {/* Table - Virtualized */}
      <div 
        ref={containerRef}
        className="overflow-auto max-h-[600px] rounded-2xl shadow-lg border border-gray-200 relative"
      >
        <table className="w-full text-sm font-sans border-collapse">
          <thead className="sticky top-0 z-10 shadow-sm">
            <tr className="text-white">
              <th className="bg-blue-900 text-left p-4 w-1/3">Representante (Rep 3)</th>
              <th className="bg-green-600 text-center p-4">Ativo</th>
              <th className="bg-orange-400 text-center p-4">Semi-Ativo</th>
              <th className="bg-red-600 text-center p-4">Inativo</th>
              <th className="bg-gray-900 text-center p-4">Total Geral</th>
            </tr>
          </thead>
          <tbody>
            {tableData.length === 0 ? (
               <tr><td colSpan={5} className="p-8 text-center text-gray-500 bg-gray-50">Nenhum dado para este período</td></tr>
            ) : (
              <>
                {paddingTop > 0 && (
                  <tr style={{ height: `${paddingTop}px` }}>
                    <td colSpan={5} />
                  </tr>
                )}
                {virtualItems.map((index) => {
                  const row = tableData[index];
                  return (
                    <tr key={index} className="bg-white border-b border-gray-100 hover:bg-blue-50 transition-colors text-gray-800 h-[57px] box-border">
                      <td className="p-3 px-4 font-medium border-r border-gray-100">{row.representativeName}</td>

                      {/* Active Cell */}
                      <td className="p-3 px-4 text-center border-r border-gray-100">
                        {row.active > 0 ? (
                           <button 
                             onClick={() => onDrillDown({ rep: row.representativeName, supervisor: selectedSupervisor, status: ClientStatus.ACTIVE })}
                             className="px-3 py-1 rounded-full bg-green-100 text-green-800 font-bold text-xs hover:bg-green-200 transition-colors"
                           >
                             {row.active}
                           </button>
                        ) : <span className="text-gray-300">-</span>}
                      </td>

                      {/* Semi-Active Cell */}
                      <td className="p-3 px-4 text-center border-r border-gray-100">
                        {row.semiActive > 0 ? (
                           <button 
                            onClick={() => onDrillDown({ rep: row.representativeName, supervisor: selectedSupervisor, status: ClientStatus.SEMI_ACTIVE })}
                            className="px-3 py-1 rounded-full bg-orange-100 text-orange-800 font-bold text-xs hover:bg-orange-200 transition-colors"
                           >
                             {row.semiActive}
                           </button>
                        ) : <span className="text-gray-300">-</span>}
                      </td>

                      {/* Inactive Cell */}
                      <td className="p-3 px-4 text-center border-r border-gray-100">
                        {row.inactive > 0 ? (
                           <button 
                            onClick={() => onDrillDown({ rep: row.representativeName, supervisor: selectedSupervisor, status: ClientStatus.INACTIVE })}
                            className="px-3 py-1 rounded-full bg-red-100 text-red-800 font-bold text-xs hover:bg-red-200 transition-colors"
                           >
                             {row.inactive}
                           </button>
                        ) : <span className="text-gray-300">-</span>}
                      </td>

                      {/* Total Cell */}
                      <td className="p-3 px-4 text-center font-bold text-gray-700">
                        {row.total > 0 ? (
                          <button 
                            onClick={() => onDrillDown({ rep: row.representativeName, supervisor: selectedSupervisor })}
                            className="px-3 py-1 rounded-full bg-gray-200 text-gray-900 font-bold text-xs hover:bg-gray-300 transition-colors"
                          >
                            {row.total}
                          </button>
                        ) : 0}
                      </td>
                    </tr>
                  );
                })}
                {paddingBottom > 0 && (
                  <tr style={{ height: `${paddingBottom}px` }}>
                    <td colSpan={5} />
                  </tr>
                )}
              </>
            )}
          </tbody>
          <tfoot className="sticky bottom-0 z-10">
            <tr className="text-white font-bold text-center shadow-[0_-1px_3px_rgba(0,0,0,0.1)]">
              <td className="bg-blue-900 text-left p-4">Total Geral</td>
              <td 
                className="bg-green-600 p-4 cursor-pointer hover:bg-green-500 transition-colors"
                onClick={() => onDrillDown({ supervisor: selectedSupervisor, status: ClientStatus.ACTIVE })}
                title="Ver detalhes de Ativos"
              >
                {totals.active}
              </td>
              <td 
                className="bg-orange-500 p-4 cursor-pointer hover:bg-orange-400 transition-colors"
                onClick={() => onDrillDown({ supervisor: selectedSupervisor, status: ClientStatus.SEMI_ACTIVE })}
                title="Ver detalhes de Semi-ativos"
              >
                {totals.semi}
              </td>
              <td 
                className="bg-red-700 p-4 cursor-pointer hover:bg-red-600 transition-colors"
                onClick={() => onDrillDown({ supervisor: selectedSupervisor, status: ClientStatus.INACTIVE })}
                title="Ver detalhes de Inativos"
              >
                {totals.inactive}
              </td>
              <td 
                className="bg-gray-900 p-4 cursor-pointer hover:bg-gray-800 transition-colors"
                onClick={() => onDrillDown({ supervisor: selectedSupervisor })}
                title="Ver detalhes Geral"
              >
                {totals.total}
              </td>
            </tr>
          </tfoot>
        </table>
      </div>
    </div>
  );
};

export default SupervisorTab;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { ClientRecord, RepViewRow, ClientStatus } from '../types';
import { useVirtualizer } from '../hooks/useVirtualizer';

interface RepresentativeTabProps {
  data: ClientRecord[];
  onExport: (data: any[], filename: string) => void;
  onDrillDown: (filters: { rep?: string; city?: string; status?: ClientStatus | ClientStatus[] }) => void;
}

const ITEM_HEIGHT = 56; // Estimated row height

// Persistence Keys
const KEY_REP_NAME = 'MILLENIUM_PREF_REP_NAME';
const KEY_DATE_START = 'MILLENIUM_PREF_DATE_START';
const KEY_DATE_END = 'MILLENIUM_PREF_DATE_END';

type SortKey = keyof RepViewRow;

const RepresentativeTab: React.FC<RepresentativeTabProps> = ({ data, onExport, onDrillDown }) => {
  // Initialize state from LocalStorage
  const [selectedRep, setSelectedRep] = useState<string>(() => localStorage.getItem(KEY_REP_NAME) || '');
  const [startDate, setStartDate] = useState(() => localStorage.getItem(KEY_DATE_START) || '2023-01-01');
  const [endDate, setEndDate] = useState(() => localStorage.getItem(KEY_DATE_END) || new Date().toISOString().split('T')[0]);

  // Sort State
  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'positiveCount', // Default sort by count
    direction: 'desc'
  });

  // Persist changes
  useEffect(() => { if (selectedRep) localStorage.setItem(KEY_REP_NAME, selectedRep); }, [selectedRep]);
  useEffect(() => { localStorage.setItem(KEY_DATE_START, startDate); }, [startDate]);
  useEffect(() => { localStorage.setItem(KEY_DATE_END, endDate); }, [endDate]);

  // Searchable Select States
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState(selectedRep); // Init search term with selected value
  const dropdownRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Sync SearchTerm if selectedRep changes externally or on load
  useEffect(() => {
    if (selectedRep) setSearchTerm(selectedRep);
  }, [selectedRep]);

  // Extract unique reps from rep3 column
  const representatives = useMemo(() => {
    const reps = Array.from(new Set(data.map(d => d.rep3))).sort();
    return reps;
  }, [data]);

  // Set default selected rep if empty or invalid, respecting potential filtered list
  useEffect(() => {
    // Only set default if we have data and current selection is not valid in the current dataset
    if (representatives.length > 0) {
      if (!selectedRep || !representatives.includes(selectedRep)) {
        const initial = representatives[0];
        setSelectedRep(initial);
        setSearchTerm(initial);
      }
    }
  }, [representatives, selectedRep]);

  // Handle clicking outside to close dropdown
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsDropdownOpen(false);
        // If user typed something invalid and clicked out, revert to selectedRep
        if (!representatives.includes(searchTerm) && searchTerm !== '') {
           setSearchTerm(selectedRep);
        } else if (searchTerm === '') {
           setSearchTerm(selectedRep);
        }
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [dropdownRef, selectedRep, searchTerm, representatives]);

  // Filtered Options for the Dropdown
  const filteredOptions = useMemo(() => {
    if (!searchTerm) return representatives;
    return representatives.filter(r => 
      r.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [representatives, searchTerm]);

  const handleSelectRep = (rep: string) => {
    setSelectedRep(rep);
    setSearchTerm(rep);
    setIsDropdownOpen(false);
  };

  const handleClearFilters = () => {
    // Reset Dates to default
    setStartDate('2023-01-01');
    setEndDate(new Date().toISOString().split('T')[0]);

    // Reset Representative to first available
    if (representatives.length > 0) {
      const initial = representatives[0];
      setSelectedRep(initial);
      setSearchTerm(initial);
    } else {
      setSelectedRep('');
      setSearchTerm('');
    }
  };

  const handleSort = (key: SortKey) => {
    setSortConfig(current => ({
      key,
      direction: current.key === key && current.direction === 'desc' ? 'asc' : 'desc'
    }));
  };

  // Filter and Aggregate Data
  const tableData = useMemo(() => {
    if (!selectedRep) return [];

    // 1. Filter by Rep3 and Date
    const filtered = data.filter(item => {
      const matchRep = item.rep3 === selectedRep; // Using rep3
      const matchDate = item.lastPurchaseDate >= startDate && item.lastPurchaseDate <= endDate;
      // Filter now includes both ACTIVE and SEMI_ACTIVE
      const isPositive = item.status === ClientStatus.ACTIVE || item.status === ClientStatus.SEMI_ACTIVE; 
      return matchRep && matchDate && isPositive;
    });

    // 2. Group by City
    const cityMap = new Map<string, RepViewRow>();

    filtered.forEach(item => {
      const key = `${item.city} - ${item.state}`;
      if (!cityMap.has(key)) {
        cityMap.set(key, {
          city: item.city,
          state: item.state,
          positiveCount: 0,
          population: item.population
        });
      }
      const entry = cityMap.get(key)!;
      entry.positiveCount += 1;
    });

    const rows = Array.from(cityMap.values());

    // 3. Sort
    return rows.sort((a, b) => {
      const aVal = a[sortConfig.key];
      const bVal = b[sortConfig.key];

      if (aVal < bVal) return sortConfig.direction === 'asc' ? -1 : 1;
      if (aVal > bVal) return sortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });
  }, [data, selectedRep, startDate, endDate, sortConfig]);

  const totalPositivated = tableData.reduce((acc, curr) => acc + curr.positiveCount, 0);
  const totalPop = tableData.reduce((acc, curr) => acc + curr.population, 0);

  const handleExport = () => {
    const csvData = tableData.map(row => ({
      'Cidade/UF': `${row.city} - ${row.state}`,
      'Positivação (Ativos + Semi)': row.positiveCount,
      'Habitantes': row.population
    }));
    onExport(csvData, `Positivacao_${selectedRep}_${startDate}_${endDate}`);
  };

  // Virtualization
  const { virtualItems, paddingTop, paddingBottom } = useVirtualizer({
    count: tableData.length,
    itemHeight: ITEM_HEIGHT,
    containerRef: containerRef,
    overscan: 5
  });

  const renderSortIcon = (key: SortKey) => {
    if (sortConfig.key !== key) return <i className="fas fa-sort text-gray-400 opacity-30 ml-2 text-xs"></i>;
    return sortConfig.direction === 'asc' 
      ? <i className="fas fa-sort-up text-blue-400 ml-2 text-xs"></i> 
      : <i className="fas fa-sort-down text-blue-400 ml-2 text-xs"></i>;
  };

  return (
    <div className="flex flex-col gap-6">
      {/* Header / Filters */}
      <div className="bg-yellow-50 p-4 border border-yellow-200 shadow-sm rounded-2xl">

        <div className="flex flex-col lg:flex-row justify-between items-end gap-4 bg-white p-4 rounded-xl shadow-inner border border-yellow-100">

          {/* SEARCHABLE REPRESENTATIVE INPUT */}
          <div className="w-full lg:w-1/3 relative" ref={dropdownRef}>
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1 ml-1">Selecione o Representante</label>
            <div className="relative group">
              <input 
                type="text"
                value={searchTerm}
                onChange={(e) => {
                  setSearchTerm(e.target.value);
                  setIsDropdownOpen(true);
                }}
                onClick={() => setIsDropdownOpen(true)}
                placeholder="Digite para buscar..."
                className="w-full p-2.5 pl-3 pr-10 border border-gray-300 bg-gray-50 rounded-lg text-sm text-gray-700 font-semibold focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all shadow-sm"
              />
              <div 
                className="absolute inset-y-0 right-0 flex items-center px-3 cursor-pointer text-gray-500 hover:text-blue-600"
                onClick={() => setIsDropdownOpen(!isDropdownOpen)}
              >
                <i className={`fas fa-chevron-down text-xs transition-transform duration-200 ${isDropdownOpen ? 'transform rotate-180' : ''}`}></i>
              </div>
            </div>

            {/* DROPDOWN LIST */}
            {isDropdownOpen && (
              <ul className="absolute z-50 w-full mt-1 bg-white border border-gray-200 rounded-lg shadow-xl max-h-60 overflow-y-auto animate-fade-in">
                {filteredOptions.length === 0 ? (
